/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE families (
    id INTEGER PRIMARY KEY,
    name TEXT UNIQUE NOT NULL,
    category TEXT NOT NULL,  -- paradigm, typing, memory, execution, effects, concurrency
    description TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE family_characteristics (
    id INTEGER PRIMARY KEY,
    family_id INTEGER REFERENCES families(id) ON DELETE CASCADE,
    dimension TEXT NOT NULL,  -- typing, memory, control, data, meta
    characteristic TEXT NOT NULL,
    value TEXT NOT NULL,
    notes TEXT,
    UNIQUE(family_id, dimension, characteristic)
);
CREATE TABLE family_relationships (
    id INTEGER PRIMARY KEY,
    from_family_id INTEGER REFERENCES families(id) ON DELETE CASCADE,
    to_family_id INTEGER REFERENCES families(id) ON DELETE CASCADE,
    relationship_type TEXT NOT NULL,  -- influenced_by, similar_to, subset_of
    notes TEXT,
    UNIQUE(from_family_id, to_family_id, relationship_type)
);
CREATE TABLE languages (
    id INTEGER PRIMARY KEY,
    name TEXT UNIQUE NOT NULL,
    version TEXT,
    tier INTEGER NOT NULL,  -- 1, 2, or 3
    description TEXT,
    popularity_tiobe INTEGER,
    popularity_so REAL,
    github_repos TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE language_families (
    language_id INTEGER REFERENCES languages(id) ON DELETE CASCADE,
    family_id INTEGER REFERENCES families(id) ON DELETE CASCADE,
    is_primary BOOLEAN DEFAULT FALSE,
    PRIMARY KEY (language_id, family_id)
);
CREATE TABLE language_features (
    id INTEGER PRIMARY KEY,
    language_id INTEGER REFERENCES languages(id) ON DELETE CASCADE,
    dimension TEXT NOT NULL,  -- typing, memory, control, data, meta
    feature TEXT NOT NULL,
    value TEXT NOT NULL,
    notes TEXT,
    UNIQUE(language_id, dimension, feature)
);
CREATE TABLE language_syntax (
    id INTEGER PRIMARY KEY,
    language_id INTEGER REFERENCES languages(id) ON DELETE CASCADE,
    pattern_name TEXT NOT NULL,  -- function_def, type_def, module_def, import
    pattern TEXT NOT NULL,
    notes TEXT,
    UNIQUE(language_id, pattern_name)
);
CREATE TABLE language_gaps (
    id INTEGER PRIMARY KEY,
    language_id INTEGER REFERENCES languages(id) ON DELETE CASCADE,
    gap_description TEXT NOT NULL,
    severity TEXT,  -- minor, moderate, major
    workaround TEXT
);
CREATE TABLE ir_patterns (
    id INTEGER PRIMARY KEY,
    skill_name TEXT NOT NULL,
    source_lang TEXT NOT NULL,
    target_lang TEXT NOT NULL,
    pattern_type TEXT NOT NULL,  -- type_mapping, idiom, gap, error, concurrency
    category TEXT,               -- subcategory within type
    source_pattern TEXT NOT NULL,
    target_pattern TEXT,
    is_lossy BOOLEAN DEFAULT FALSE,
    severity TEXT,               -- for gaps: impossible, lossy, structural, idiomatic
    mitigation TEXT,
    notes TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
PRAGMA writable_schema=ON;
    source_pattern, target_pattern, notes,
    content=''ir_patterns'',
    content_rowid=''id''
)');
CREATE TABLE IF NOT EXISTS 'patterns_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'patterns_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'patterns_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'patterns_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE semantic_gaps (
    id INTEGER PRIMARY KEY,
    from_family_id INTEGER REFERENCES families(id),
    to_family_id INTEGER REFERENCES families(id),
    gap_category TEXT NOT NULL,  -- impossible, lossy, structural, idiomatic, runtime, semantic
    concept TEXT NOT NULL,
    description TEXT,
    severity TEXT NOT NULL,  -- critical, high, medium, low
    mitigation TEXT,
    automation_level TEXT,  -- none, partial, full
    notes TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE gap_patterns (
    id INTEGER PRIMARY KEY,
    name TEXT UNIQUE NOT NULL,
    category TEXT NOT NULL,  -- type_system, memory, effects, concurrency
    description TEXT,
    from_concept TEXT NOT NULL,
    to_concept TEXT NOT NULL,
    mitigation_strategy TEXT,
    example_from TEXT,
    example_to TEXT
);
CREATE TABLE decision_points (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT,
    options TEXT NOT NULL,  -- JSON array of options
    guidance TEXT,
    applicable_gaps TEXT  -- JSON array of gap IDs
);
CREATE TABLE family_conversion_difficulty (
    id INTEGER PRIMARY KEY,
    from_family_id INTEGER REFERENCES families(id),
    to_family_id INTEGER REFERENCES families(id),
    difficulty INTEGER NOT NULL,  -- 1=easy, 2=moderate, 3=hard, 4=very_hard
    notes TEXT,
    semantic_gaps TEXT,  -- JSON array of gap descriptions
    UNIQUE(from_family_id, to_family_id)
);
CREATE TABLE skill_coverage (
    id INTEGER PRIMARY KEY,
    source_lang_id INTEGER REFERENCES languages(id),
    target_lang_id INTEGER REFERENCES languages(id),
    skill_name TEXT,  -- NULL if no skill exists
    skill_path TEXT,
    is_bidirectional BOOLEAN DEFAULT FALSE,
    notes TEXT,
    UNIQUE(source_lang_id, target_lang_id)
);
CREATE TABLE ir_versions (
    id INTEGER PRIMARY KEY,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    source_language TEXT NOT NULL,
    source_path TEXT,
    extraction_tool_version TEXT,
    notes TEXT
);
CREATE TABLE ir_units (
    id INTEGER PRIMARY KEY,
    version_id INTEGER REFERENCES ir_versions(id) ON DELETE CASCADE,
    layer INTEGER NOT NULL,  -- 0-4
    unit_type TEXT NOT NULL,  -- module, type, function, binding, expression
    content_hash TEXT NOT NULL,
    content_json TEXT NOT NULL,
    UNIQUE(version_id, content_hash)
);
CREATE TABLE ir_dependencies (
    from_unit_id INTEGER REFERENCES ir_units(id) ON DELETE CASCADE,
    to_unit_id INTEGER REFERENCES ir_units(id) ON DELETE CASCADE,
    dependency_type TEXT NOT NULL,  -- uses, extends, imports, calls
    PRIMARY KEY (from_unit_id, to_unit_id, dependency_type)
);
CREATE TABLE ir_annotations (
    id INTEGER PRIMARY KEY,
    unit_id INTEGER REFERENCES ir_units(id) ON DELETE CASCADE,
    annotation_type TEXT NOT NULL,
    annotation_value TEXT NOT NULL,  -- JSON
    confidence REAL DEFAULT 1.0,
    source TEXT NOT NULL  -- explicit, inferred, default
);
CREATE TABLE ir_gap_markers (
    id INTEGER PRIMARY KEY,
    unit_id INTEGER REFERENCES ir_units(id) ON DELETE CASCADE,
    gap_type TEXT NOT NULL,
    description TEXT,
    source_concept TEXT,
    mitigations TEXT  -- JSON array
);
CREATE TABLE ir_layers (
    id INTEGER PRIMARY KEY,
    layer_num INTEGER UNIQUE NOT NULL,
    name TEXT NOT NULL,
    description TEXT,
    schema_json TEXT  -- JSON Schema for this layer
);
CREATE TABLE ir_preservation_status (
    id INTEGER PRIMARY KEY,
    unit_id INTEGER NOT NULL REFERENCES ir_units(id) ON DELETE CASCADE,
    current_level INTEGER NOT NULL CHECK(current_level >= 0 AND current_level <= 3),
    max_achievable_level INTEGER NOT NULL CHECK(max_achievable_level >= 0 AND max_achievable_level <= 3),
    blocking_gaps TEXT,  -- JSON array of gap IDs
    level_0_achieved BOOLEAN DEFAULT FALSE,
    level_1_achieved BOOLEAN DEFAULT FALSE,
    level_2_achieved BOOLEAN DEFAULT FALSE,
    level_3_achieved BOOLEAN DEFAULT FALSE,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    CHECK(current_level <= max_achievable_level)
);
CREATE TABLE ir_asymmetry_metadata (
    id INTEGER PRIMARY KEY,
    unit_id INTEGER REFERENCES ir_units(id) ON DELETE CASCADE,
    source_family TEXT NOT NULL,
    target_family TEXT NOT NULL,
    direction_difficulty INTEGER CHECK(direction_difficulty >= 1 AND direction_difficulty <= 5),
    reverse_difficulty INTEGER CHECK(reverse_difficulty >= 1 AND reverse_difficulty <= 5),
    asymmetry_ratio REAL,
    preserved_in_reverse BOOLEAN DEFAULT TRUE,
    notes TEXT,
    CHECK(direction_difficulty IS NOT NULL OR reverse_difficulty IS NOT NULL)
);
CREATE TABLE ir_decision_resolutions (
    id INTEGER PRIMARY KEY,
    unit_id INTEGER NOT NULL REFERENCES ir_units(id) ON DELETE CASCADE,
    decision_point_id TEXT NOT NULL,
    chosen_option TEXT NOT NULL,
    rationale TEXT,
    resolved_by TEXT NOT NULL CHECK(resolved_by IN ('human', 'heuristic', 'default')),
    resolved_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    confidence REAL CHECK(confidence IS NULL OR (confidence >= 0.0 AND confidence <= 1.0)),
    overridable BOOLEAN DEFAULT TRUE
);
CREATE TABLE ir_gap_markers_v2 (
    id INTEGER PRIMARY KEY,
    unit_id INTEGER REFERENCES ir_units(id) ON DELETE CASCADE,
    -- Original columns
    gap_type TEXT NOT NULL CHECK(gap_type IN ('impossible', 'lossy', 'structural', 'idiomatic', 'runtime', 'semantic')),
    description TEXT,
    source_concept TEXT,
    mitigations TEXT,  -- JSON array
    -- Phase 4 extensions
    gap_pattern_id TEXT,  -- TS-001, MM-002, CC-001, EF-001, etc.
    severity TEXT CHECK(severity IN ('critical', 'high', 'medium', 'low')),
    target_concept TEXT,
    decision_point_id TEXT,  -- DP-001 through DP-016
    preservation_level INTEGER CHECK(preservation_level >= 0 AND preservation_level <= 3),
    automation_level TEXT CHECK(automation_level IN ('none', 'partial', 'full')),
    affected_layers TEXT,  -- JSON array [0,1,2,3,4]
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
CREATE VIEW v_language_families AS
SELECT
    l.name as language,
    l.tier,
    GROUP_CONCAT(f.name, ', ') as families
FROM languages l
LEFT JOIN language_families lf ON l.id = lf.language_id
LEFT JOIN families f ON lf.family_id = f.id
GROUP BY l.id;
CREATE VIEW v_skill_coverage AS
SELECT
    sl.name as source_lang,
    tl.name as target_lang,
    sc.skill_name,
    sc.is_bidirectional
FROM skill_coverage sc
JOIN languages sl ON sc.source_lang_id = sl.id
JOIN languages tl ON sc.target_lang_id = tl.id;
CREATE VIEW v_family_difficulty AS
SELECT
    ff.name as from_family,
    tf.name as to_family,
    fcd.difficulty,
    fcd.notes
FROM family_conversion_difficulty fcd
JOIN families ff ON fcd.from_family_id = ff.id
JOIN families tf ON fcd.to_family_id = tf.id;
CREATE VIEW v_preservation_summary AS
SELECT
    ps.id, ps.unit_id, iu.unit_type, iu.layer, iv.source_language,
    ps.current_level, ps.max_achievable_level,
    CASE ps.current_level WHEN 0 THEN 'Syntactic' WHEN 1 THEN 'Semantic'
         WHEN 2 THEN 'Idiomatic' WHEN 3 THEN 'Optimized' END AS current_level_name,
    CASE ps.max_achievable_level WHEN 0 THEN 'Syntactic' WHEN 1 THEN 'Semantic'
         WHEN 2 THEN 'Idiomatic' WHEN 3 THEN 'Optimized' END AS max_level_name,
    ps.blocking_gaps, ps.level_0_achieved, ps.level_1_achieved,
    ps.level_2_achieved, ps.level_3_achieved, ps.updated_at
FROM ir_preservation_status ps
JOIN ir_units iu ON ps.unit_id = iu.id
JOIN ir_versions iv ON iu.version_id = iv.id;
CREATE VIEW v_gaps_by_pattern AS
SELECT
    gm.gap_pattern_id, gm.gap_type, gm.severity,
    COUNT(*) AS gap_count,
    GROUP_CONCAT(DISTINCT gm.source_concept, '; ') AS source_concepts,
    GROUP_CONCAT(DISTINCT gm.target_concept, '; ') AS target_concepts,
    AVG(gm.preservation_level) AS avg_preservation_level,
    SUM(CASE WHEN gm.automation_level = 'none' THEN 1 ELSE 0 END) AS manual_count,
    SUM(CASE WHEN gm.automation_level = 'partial' THEN 1 ELSE 0 END) AS partial_count,
    SUM(CASE WHEN gm.automation_level = 'full' THEN 1 ELSE 0 END) AS full_count
FROM ir_gap_markers_v2 gm
WHERE gm.gap_pattern_id IS NOT NULL
GROUP BY gm.gap_pattern_id, gm.gap_type, gm.severity
ORDER BY gap_count DESC;
CREATE VIEW v_decision_audit AS
SELECT
    dr.id, dr.unit_id, iu.unit_type, iv.source_language,
    dr.decision_point_id, dp.name AS decision_name, dp.description AS decision_description,
    dr.chosen_option, dr.rationale, dr.resolved_by, dr.confidence,
    dr.overridable, dr.resolved_at
FROM ir_decision_resolutions dr
JOIN ir_units iu ON dr.unit_id = iu.id
JOIN ir_versions iv ON iu.version_id = iv.id
LEFT JOIN decision_points dp ON dr.decision_point_id = dp.id;
CREATE TRIGGER ir_patterns_ai AFTER INSERT ON ir_patterns BEGIN
    VALUES (new.id, new.source_pattern, new.target_pattern, new.notes);
END;
CREATE TRIGGER ir_patterns_ad AFTER DELETE ON ir_patterns BEGIN
    VALUES ('delete', old.id, old.source_pattern, old.target_pattern, old.notes);
END;
CREATE TRIGGER ir_patterns_au AFTER UPDATE ON ir_patterns BEGIN
    VALUES ('delete', old.id, old.source_pattern, old.target_pattern, old.notes);
    VALUES (new.id, new.source_pattern, new.target_pattern, new.notes);
END;
CREATE TRIGGER trg_preservation_updated
AFTER UPDATE ON ir_preservation_status
BEGIN
    UPDATE ir_preservation_status SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
END;
CREATE TRIGGER trg_asymmetry_ratio_insert
AFTER INSERT ON ir_asymmetry_metadata
WHEN NEW.direction_difficulty IS NOT NULL AND NEW.reverse_difficulty IS NOT NULL AND NEW.asymmetry_ratio IS NULL
BEGIN
    UPDATE ir_asymmetry_metadata
    SET asymmetry_ratio = CAST(NEW.direction_difficulty AS REAL) / CAST(NEW.reverse_difficulty AS REAL)
    WHERE id = NEW.id;
END;
CREATE TRIGGER trg_asymmetry_ratio_update
AFTER UPDATE OF direction_difficulty, reverse_difficulty ON ir_asymmetry_metadata
WHEN NEW.direction_difficulty IS NOT NULL AND NEW.reverse_difficulty IS NOT NULL
BEGIN
    UPDATE ir_asymmetry_metadata
    SET asymmetry_ratio = CAST(NEW.direction_difficulty AS REAL) / CAST(NEW.reverse_difficulty AS REAL)
    WHERE id = NEW.id;
END;
CREATE TRIGGER trg_decision_validate
BEFORE INSERT ON ir_decision_resolutions
WHEN NEW.decision_point_id NOT LIKE 'DP-%'
BEGIN
    SELECT RAISE(ABORT, 'decision_point_id must follow pattern DP-XXX');
END;
CREATE INDEX idx_patterns_skill ON ir_patterns(skill_name);
CREATE INDEX idx_patterns_type ON ir_patterns(pattern_type);
CREATE INDEX idx_patterns_langs ON ir_patterns(source_lang, target_lang);
CREATE INDEX idx_gaps_families ON semantic_gaps(from_family_id, to_family_id);
CREATE INDEX idx_gaps_category ON semantic_gaps(gap_category);
CREATE INDEX idx_gaps_severity ON semantic_gaps(severity);
CREATE INDEX idx_units_version ON ir_units(version_id);
CREATE INDEX idx_units_layer ON ir_units(layer);
CREATE INDEX idx_deps_from ON ir_dependencies(from_unit_id);
CREATE INDEX idx_deps_to ON ir_dependencies(to_unit_id);
CREATE INDEX idx_preservation_unit ON ir_preservation_status(unit_id);
CREATE INDEX idx_preservation_level ON ir_preservation_status(current_level);
CREATE INDEX idx_preservation_max ON ir_preservation_status(max_achievable_level);
CREATE INDEX idx_asymmetry_unit ON ir_asymmetry_metadata(unit_id);
CREATE INDEX idx_asymmetry_families ON ir_asymmetry_metadata(source_family, target_family);
CREATE INDEX idx_asymmetry_ratio ON ir_asymmetry_metadata(asymmetry_ratio);
CREATE INDEX idx_decisions_unit ON ir_decision_resolutions(unit_id);
CREATE INDEX idx_decisions_point ON ir_decision_resolutions(decision_point_id);
CREATE INDEX idx_decisions_resolved_by ON ir_decision_resolutions(resolved_by);
CREATE INDEX idx_gaps_v2_unit ON ir_gap_markers_v2(unit_id);
CREATE INDEX idx_gaps_v2_type ON ir_gap_markers_v2(gap_type);
CREATE INDEX idx_gaps_v2_pattern ON ir_gap_markers_v2(gap_pattern_id);
CREATE INDEX idx_gaps_v2_severity ON ir_gap_markers_v2(severity);
CREATE INDEX idx_gaps_v2_decision ON ir_gap_markers_v2(decision_point_id);
PRAGMA writable_schema=OFF;
COMMIT;
