INSERT INTO families VALUES(1,'ML/Functional','paradigm',unistr('Languages derived from ML (Meta Language) tradition emphasizing\u000aimmutability, pattern matching, algebraic data types, and type inference.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(2,'BEAM/Actor','paradigm',unistr('Languages running on the BEAM virtual machine (Erlang VM),\u000aemphasizing fault tolerance, distribution, and the actor model.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(3,'LISP/Homoiconic','paradigm',unistr('Languages in the LISP tradition featuring homoiconicity (code as data),\u000apowerful macro systems, and dynamic typing.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(4,'Systems','paradigm',unistr('Languages designed for systems programming with direct hardware access,\u000amanual or semi-automatic memory management, and performance focus.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(5,'Managed OOP','paradigm',unistr('Class-based object-oriented languages with managed memory (GC),\u000aemphasizing inheritance, encapsulation, and nominal typing.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(6,'Dynamic','paradigm',unistr('Dynamically-typed languages emphasizing flexibility, rapid development,\u000aand runtime metaprogramming.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(7,'Apple Platform','paradigm',unistr('Languages designed for Apple platforms (macOS, iOS),\u000afeaturing reference counting and platform framework integration.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(8,'Gradual Typing','feature',unistr('Type systems that allow mixing typed and untyped code,\u000aenabling incremental adoption of static typing.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(9,'Ownership/Linear Types','feature',unistr('Type systems that track resource ownership and lifetimes,\u000aenabling memory safety without garbage collection.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(10,'Actor Model','feature',unistr('Concurrency model where actors are isolated units of computation\u000athat communicate via message passing.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(11,'Dependent Types','feature',unistr('Type systems where types can depend on values,\u000aenabling proofs and very precise specifications.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(12,'Logic Programming','specialized',unistr('Languages based on formal logic, where programs are logical\u000astatements and execution is logical inference.'),'2026-02-05 02:48:05');
INSERT INTO families VALUES(13,'Array Programming','specialized',unistr('Languages where operations apply to entire arrays/matrices,\u000aemphasizing concise notation and implicit iteration.'),'2026-02-05 02:48:05');
