INSERT INTO language_gaps VALUES(1,2,'No memory safety','critical','Static analyzers, sanitizers, careful review');
INSERT INTO language_gaps VALUES(2,2,'No bounds checking','critical','Manual checks, secure functions');
INSERT INTO language_gaps VALUES(3,2,'NULL pointer risks','high','Defensive programming, static analysis');
INSERT INTO language_gaps VALUES(4,2,'No namespaces','moderate','Prefix conventions (lib_function)');
INSERT INTO language_gaps VALUES(5,2,'No generics','moderate','void*, macros, code generation');
INSERT INTO language_gaps VALUES(6,3,'No static types','moderate','Use spec, Schema, or Typed Clojure');
INSERT INTO language_gaps VALUES(7,3,'JVM startup time','moderate','GraalVM native-image, keep REPL running');
INSERT INTO language_gaps VALUES(8,3,'Stack not tail-call optimized','minor','Use loop/recur, trampoline');
INSERT INTO language_gaps VALUES(9,3,'No pattern matching built-in','minor','Use core.match library');
INSERT INTO language_gaps VALUES(10,6,'Complex syntax and feature interactions','high','Follow C++ Core Guidelines');
INSERT INTO language_gaps VALUES(11,6,'Long compile times (templates)','moderate','Precompiled headers, modules, explicit instantiation');
INSERT INTO language_gaps VALUES(12,6,'ABI stability issues','moderate','Pimpl idiom, C ABI wrappers');
INSERT INTO language_gaps VALUES(13,6,'Undefined behavior risks','moderate','Sanitizers, static analysis');
INSERT INTO language_gaps VALUES(14,7,'No static types','moderate','Use Dialyzer, typespecs');
INSERT INTO language_gaps VALUES(15,7,'Immutable only (no local mutation)','minor','Use recursion, comprehensions');
INSERT INTO language_gaps VALUES(16,7,'OTP learning curve','moderate','Start with Task, GenServer basics');
INSERT INTO language_gaps VALUES(17,7,'No lazy evaluation by default','minor','Use Stream module');
INSERT INTO language_gaps VALUES(18,8,'No higher-kinded types','moderate','Use specific types, phantom types');
INSERT INTO language_gaps VALUES(19,8,'No type classes','moderate','Use module patterns, explicit passing');
INSERT INTO language_gaps VALUES(20,8,'No custom operators','minor','Use descriptive function names');
INSERT INTO language_gaps VALUES(21,8,'Limited JS interop (ports only)','moderate','Design port-based architecture');
INSERT INTO language_gaps VALUES(22,8,'No native/FFI in 0.19','moderate','Use ports or web components');
INSERT INTO language_gaps VALUES(23,9,'No static types','moderate','Use Dialyzer, specs');
INSERT INTO language_gaps VALUES(24,9,'Prolog-inspired syntax unfamiliar','moderate','Learn idioms, reference docs');
INSERT INTO language_gaps VALUES(25,9,'Records are compile-time only','minor','Use maps for dynamic structures');
INSERT INTO language_gaps VALUES(26,9,'Syntax can be terse','moderate','Use Elixir for friendlier syntax');
INSERT INTO language_gaps VALUES(27,11,'.NET null leaks into F#','moderate','Use Option, enable nullable reference types');
INSERT INTO language_gaps VALUES(28,11,'Mutable by default in .NET interop','minor','Wrap in F# types, use immutable interfaces');
INSERT INTO language_gaps VALUES(29,11,'Limited higher-kinded types','moderate','Use computation expressions, SRTP');
INSERT INTO language_gaps VALUES(30,11,'No pattern matching in lambdas','minor','Use match expression, function keyword');
INSERT INTO language_gaps VALUES(31,12,'No macros','minor','Use code generation, FFI to Elixir');
INSERT INTO language_gaps VALUES(32,12,'No interactive REPL','minor','Use gleam run for scripts');
INSERT INTO language_gaps VALUES(33,12,'Smaller ecosystem','moderate','Use Erlang/Elixir libraries via FFI');
INSERT INTO language_gaps VALUES(34,12,'No type classes','moderate','Use module patterns');
INSERT INTO language_gaps VALUES(35,13,'No sum types/enums','moderate','Interfaces, const iota, sealed interfaces');
INSERT INTO language_gaps VALUES(36,13,'Nil interface vs nil pointer','moderate','Careful nil checks, typed nils');
INSERT INTO language_gaps VALUES(37,13,'No immutability','minor','Convention, unexported fields');
INSERT INTO language_gaps VALUES(38,13,'Verbose error handling','moderate','Error wrapping, custom error types');
INSERT INTO language_gaps VALUES(39,14,'Lazy evaluation can cause space leaks','moderate','Use strict data types, BangPatterns');
INSERT INTO language_gaps VALUES(40,14,'Partial functions (head, tail)','moderate','Use safe alternatives, -Wincomplete-patterns');
INSERT INTO language_gaps VALUES(41,14,'String as [Char] is inefficient','minor','Use Text or ByteString');
INSERT INTO language_gaps VALUES(42,14,'Record field name collisions','moderate','Use DuplicateRecordFields, OverloadedRecordDot');
INSERT INTO language_gaps VALUES(43,15,'Null pointer exceptions','high','Use Optional, @Nullable annotations');
INSERT INTO language_gaps VALUES(44,15,'Checked exceptions verbosity','moderate','Use unchecked exceptions, RuntimeException');
INSERT INTO language_gaps VALUES(45,15,'Type erasure limits','moderate','Use class tokens, consider Kotlin');
INSERT INTO language_gaps VALUES(46,15,'Verbosity (pre-records)','minor','Use records (Java 14+), Lombok');
INSERT INTO language_gaps VALUES(47,16,'No static types','high','Use TypeScript');
INSERT INTO language_gaps VALUES(48,16,'Type coercion surprises','moderate','Use === instead of ==');
INSERT INTO language_gaps VALUES(49,16,'this binding confusion','moderate','Arrow functions, explicit binding');
INSERT INTO language_gaps VALUES(50,16,'null vs undefined','minor','Use ?? operator');
INSERT INTO language_gaps VALUES(51,17,'JVM-only features for full Kotlin','moderate','Use Kotlin Multiplatform');
INSERT INTO language_gaps VALUES(52,17,'No union types','minor','Use sealed classes');
INSERT INTO language_gaps VALUES(53,17,'Gradle complexity','moderate','Use Kotlin DSL, convention plugins');
INSERT INTO language_gaps VALUES(54,18,'Dynamic typing risks','high','Use nullability annotations, Swift interop');
INSERT INTO language_gaps VALUES(55,18,'No namespaces','moderate','Use class prefixes (NS, UI, etc.)');
INSERT INTO language_gaps VALUES(56,18,'Header/implementation split','moderate','Use categories, migrate to Swift');
INSERT INTO language_gaps VALUES(57,18,'Verbose syntax','moderate','Use modern features, migrate to Swift');
INSERT INTO language_gaps VALUES(58,21,'No static type enforcement','moderate','Use mypy/pyright for static analysis');
INSERT INTO language_gaps VALUES(59,21,'GIL limits true parallelism','moderate','Use multiprocessing or async for I/O');
INSERT INTO language_gaps VALUES(60,21,'No tail call optimization','minor','Use iteration instead of recursion');
INSERT INTO language_gaps VALUES(61,21,'Mutable default arguments','minor','Use None default, assign in function');
INSERT INTO language_gaps VALUES(62,22,'Pre-1.0, API may change','high','Track language updates, use stable features');
INSERT INTO language_gaps VALUES(63,22,'Limited ecosystem (new language)','moderate','Build needed libraries, use FFI');
INSERT INTO language_gaps VALUES(64,22,'No exceptions (by design)','minor','Use Result/tags for all errors');
INSERT INTO language_gaps VALUES(65,22,'Limited platform selection','moderate','Create custom platforms as needed');
INSERT INTO language_gaps VALUES(66,22,'Documentation still developing','moderate','Reference source code, community Discord');
INSERT INTO language_gaps VALUES(67,23,'No static types','moderate','Use RBS, Sorbet');
INSERT INTO language_gaps VALUES(68,23,'GIL limits parallelism','moderate','Use Ractor (Ruby 3+), multiprocessing');
INSERT INTO language_gaps VALUES(69,23,'Slow startup','moderate','Use bootsnap, YJIT');
INSERT INTO language_gaps VALUES(70,23,'Metaprogramming can obscure','minor','Follow conventions, document');
INSERT INTO language_gaps VALUES(71,24,'Steep learning curve (borrow checker)','high','Start with owned types, learn borrowing gradually');
INSERT INTO language_gaps VALUES(72,24,'Long compile times','moderate','Use cargo check, incremental compilation');
INSERT INTO language_gaps VALUES(73,24,'Orphan rules limit trait impls','moderate','Newtype pattern, wrapper types');
INSERT INTO language_gaps VALUES(74,24,'Async ecosystem fragmentation','moderate','Choose runtime (tokio/async-std) early');
INSERT INTO language_gaps VALUES(75,25,'Null exists despite Option','moderate','Enable strict null checking, avoid null');
INSERT INTO language_gaps VALUES(76,25,'Implicit complexity (Scala 2)','moderate','Migrate to given/using (Scala 3)');
INSERT INTO language_gaps VALUES(77,25,'JVM startup time','minor','GraalVM native-image, Scala Native');
INSERT INTO language_gaps VALUES(78,25,'Scala 2 vs 3 migration','moderate','Use Scala 3 cross-building, scalafix');
INSERT INTO language_gaps VALUES(79,27,'Apple platform bias','moderate','Use SwiftPM for cross-platform');
INSERT INTO language_gaps VALUES(80,27,'ARC retain cycles','moderate','Use weak/unowned references');
INSERT INTO language_gaps VALUES(81,27,'No full reflection','minor','Use Mirror for limited reflection');
INSERT INTO language_gaps VALUES(82,27,'Rapid language evolution','minor','Pin Swift version, follow proposals');
INSERT INTO language_gaps VALUES(83,28,'Types erased at runtime','moderate','Use type guards, zod/io-ts for runtime validation');
INSERT INTO language_gaps VALUES(84,28,'any bypasses type checking','minor','Use unknown instead, enable noImplicitAny');
INSERT INTO language_gaps VALUES(85,28,'No pattern matching','moderate','Use discriminated unions + switch');
INSERT INTO language_gaps VALUES(86,28,'Null vs undefined distinction','minor','Use strictNullChecks, prefer undefined');
INSERT INTO language_gaps VALUES(87,28,'No true immutability','minor','Use readonly modifier, as const');
INSERT INTO language_gaps VALUES(88,29,'Pre-1.0, API may change','high','Track releases, pin versions');
INSERT INTO language_gaps VALUES(89,29,'Smaller ecosystem','moderate','Use C libraries, build own');
INSERT INTO language_gaps VALUES(90,29,'No runtime polymorphism','minor','Use tagged unions, comptime');
INSERT INTO language_gaps VALUES(91,29,'Manual memory management','moderate','Use arena allocators, defer');
