INSERT INTO ir_patterns VALUES(48,'convert-c-cpp','c','cpp','idiom','general','Memory Management (malloc/free → RAII)','',0,NULL,NULL,unistr('- `std::vector` manages memory automatically (RAII)\u000a- No risk of memory leaks or use-after-free\u000a- Return by value is efficient with move semantics\u000a- Bounds checking available with `.at(i)` instead of `[]`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(49,'convert-c-cpp','c','cpp','idiom','general','Strings (char* → std::string)','',0,NULL,NULL,unistr('- `std::string` manages memory automatically\u000a- No buffer overflow risks\u000a- Rich API for string manipulation\u000a- Concatenation via `operator+`\u000a- Efficient move semantics for returns'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(50,'convert-c-cpp','c','cpp','idiom','error','Error Handling (Error Codes → Exceptions/Optional)','',0,NULL,NULL,unistr('- `std::optional` avoids sentinel values and output parameters\u000a- Exceptions separate happy path from error handling\u000a- Clearer intent and less error-prone\u000a- Modern C++23 will have `std::expected<T, E>` for richer error info'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(51,'convert-c-cpp','c','cpp','idiom','general','File I/O (FILE* → RAII streams)','',0,NULL,NULL,unistr('- `std::ifstream` uses RAII: automatically closes file\u000a- No manual memory management for buffer\u000a- Exception-safe: file closed even if exception thrown\u000a- More concise and less error-prone'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(52,'convert-c-cpp','c','cpp','idiom','data-structure','Structs → Classes with Methods','',0,NULL,NULL,unistr('- Methods are grouped with data (encapsulation)\u000a- Constructors initialize members correctly\u000a- Operator overloading for natural syntax\u000a- Const correctness enforced by compiler'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(53,'convert-c-cpp','c','cpp','idiom','memory','Function Pointers → Lambdas/std::function','',0,NULL,NULL,unistr('- Lambdas are type-safe (no `void*` casting)\u000a- Can capture local variables\u000a- Inline definition for simple comparisons\u000a- `std::sort` is faster than `qsort` (inlined, type-specific)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(54,'convert-c-cpp','c','cpp','idiom','general','Macros → Templates and constexpr','',0,NULL,NULL,unistr('- Templates provide type safety\u000a- `constexpr` enables compile-time evaluation\u000a- Standard library provides `std::swap`, `std::max`, `std::min`\u000a- Better error messages than macro errors\u000a- Debugger-friendly (macros are invisible after preprocessing)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(55,'convert-c-cpp','c','cpp','idiom','general','Enums → Scoped Enums','',0,NULL,NULL,unistr('- `enum class` prevents name conflicts (scoped)\u000a- No implicit conversion to int\u000a- Stronger type safety\u000a- Explicit scoping improves readability'),'2026-02-05 02:48:05');
