INSERT INTO ir_patterns VALUES(428,'convert-clojure-elm','clojure','elm','negative','','Assuming Dynamic Typing','',0,NULL,NULL,unistr('Treating Elm like dynamically-typed Clojure\u000a\u000a```elm\u000a-- ❌ WRONG: Can''t have heterogeneous lists\u000ausers = [ { name = "Alice" }, { name = "Bob", age = 30 } ]\u000a-- ERROR: Record fields must match\u000a\u000a-- ✓ CORRECT: Define explicit type with Maybe for optional fields\u000atype alias User =\u000a    { name : String\u000a    , age : Maybe Int\u000a    }\u000a\u000ausers =\u000a    [ { name = "Alice", age = Nothing }\u000a    , { name = "Bob", age = Just 30 }\u000a    ]\u000a```'),'2026-02-05 02:48:05');
