INSERT INTO ir_patterns VALUES(695,'convert-clojure-fsharp','clojure','fsharp','idiom','type','Nil Handling to Option Type','',0,NULL,NULL,unistr('- Clojure `nil` → F# `None` (explicit absence)\u000a- Clojure `if-let` / `when-let` → F# `Option.map` / `Option.bind`\u000a- Clojure `some->` threading → F# Option combinators\u000a- F# makes nullability explicit in the type system\u000a- Pattern matching provides exhaustive checking'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(696,'convert-clojure-fsharp','clojure','fsharp','idiom','error','Exception-Based to Result Type Error Handling','',0,NULL,NULL,unistr('- Clojure exceptions → F# Result type (errors as values)\u000a- Clojure `{:ok/:error}` conventions → F# discriminated unions\u000a- Explicit error handling at compile time\u000a- Railway-oriented programming for chaining fallible operations\u000a- Type safety prevents forgetting error cases'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(697,'convert-clojure-fsharp','clojure','fsharp','idiom','concurrency','Vector Processing with Threading Macros to Pipe Operator','',0,NULL,NULL,unistr('- Clojure `->>` (thread-last) → F# `|>` (pipe forward)\u000a- Clojure `filter`/`map`/`reduce` → F# `List.filter`/`List.map`/`List.sum`\u000a- Both support lazy evaluation (seqs in Clojure, `Seq` in F#)\u000a- F# pipe operator is data-first (same as thread-last)\u000a- Tranducers → F# doesn''t have direct equivalent, use sequences'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(698,'convert-clojure-fsharp','clojure','fsharp','idiom','data-structure','Tagged Maps to Discriminated Unions','',0,NULL,NULL,unistr('- Clojure tagged maps → F# discriminated unions\u000a- Runtime `:type` tag → compile-time variant type\u000a- `defmulti`/`defmethod` → pattern matching\u000a- Exhaustive pattern matching ensures all cases handled\u000a- Type safety prevents typos in variant names'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(699,'convert-clojure-fsharp','clojure','fsharp','idiom','general','Immutable Data Updates','',0,NULL,NULL,unistr('- Clojure `assoc` → F# copy-and-update `{ r with ... }`\u000a- Clojure `update` → F# update with function\u000a- Clojure `assoc-in`/`update-in` → F# nested copy-and-update or helper functions\u000a- Both are immutable by default\u000a- F# records have named fields vs. Clojure keyword keys'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(700,'convert-clojure-fsharp','clojure','fsharp','idiom','general','Lazy Sequences','',0,NULL,NULL,unistr('- Clojure lazy seqs → F# `seq<''T>` (IEnumerable)\u000a- `iterate` → `Seq.initInfinite` / `Seq.unfold`\u000a- `for` comprehension → F# `seq { }` expression\u000a- Both evaluate lazily on demand\u000a- Both support infinite sequences safely'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(701,'convert-clojure-fsharp','clojure','fsharp','idiom','concurrency','Async and Concurrency','',0,NULL,NULL,unistr('- Clojure `future` → F# `async { }` workflows or `task { }`\u000a- Clojure `deref` (`@`) → F# `Async.RunSynchronously` or `await`\u000a- Clojure core.async channels → F# MailboxProcessor or async workflows\u000a- F# `Async.Parallel` for parallel execution\u000a- F# has both async (F# workflows) and Task (.NET tasks)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(702,'convert-clojure-fsharp','clojure','fsharp','idiom','general','Macros to Computation Expressions','',0,NULL,NULL,unistr('- Clojure macros → F# computation expressions (for DSLs)\u000a- Thread macros → F# pipe operators (built-in, not meta-programming)\u000a- Clojure compile-time code generation → F# computation builders\u000a- F# computation expressions are more constrained but type-safe\u000a- F# favors built-in language features over custom syntax'),'2026-02-05 02:48:05');
