INSERT INTO ir_patterns VALUES(858,'convert-clojure-haskell','clojure','haskell','negative','','Dynamic Type Assumptions → Static Type Requirements','',0,NULL,NULL,unistr('Clojure allows heterogeneous collections; Haskell requires homogeneous types.\u000a\u000a```clojure\u000a;; Clojure: Mixed types OK\u000a(def mixed [1 "two" :three 4.0])\u000a```\u000a\u000a```haskell\u000a-- Haskell: Need sum type for mixed\u000adata Value\u000a    = IntVal Int\u000a    | StringVal String\u000a    | KeywordVal String\u000a    | DoubleVal Double\u000a\u000amixed :: [Value]\u000amixed = [IntVal 1, StringVal "two", KeywordVal "three", DoubleVal 4.0]\u000a```\u000a\u000a**Fix:** Use algebraic data types (ADTs) to represent variants.'),'2026-02-05 02:48:05');
