INSERT INTO ir_patterns VALUES(867,'convert-clojure-haskell','clojure','haskell','idiom','concurrency','Threading Macros to Function Composition','',0,NULL,NULL,unistr('- Clojure''s `->` maps to Haskell''s `&` operator (from Data.Function)\u000a- Function composition (`.`) is more idiomatic in Haskell but reads right-to-left\u000a- Use `$` for right-associative application\u000a- Pattern: `(->> x f g h)` → `h . g . f $ x`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(868,'convert-clojure-haskell','clojure','haskell','idiom','data-structure','Destructuring','',0,NULL,NULL,unistr('- Clojure''s destructuring is runtime; Haskell''s pattern matching is compile-time\u000a- Haskell enforces exhaustive pattern matching\u000a- Record syntax provides named field access\u000a- Default values use Maybe or function parameters'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(869,'convert-clojure-haskell','clojure','haskell','idiom','general','Sequence Operations','',0,NULL,NULL,unistr('- Both languages support functional pipelines\u000a- Haskell''s list comprehensions are more powerful (guards, multiple generators)\u000a- Set.fromList is idiomatic for building sets from lists\u000a- Do-notation provides monadic abstraction over list comprehension'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(870,'convert-clojure-haskell','clojure','haskell','idiom','general','Lazy Sequences','',0,NULL,NULL,unistr('- Both languages are lazy by default for sequences\u000a- Haskell''s laziness is pervasive; Clojure''s is opt-in for sequences\u000a- Infinite data structures work the same way\u000a- Haskell''s `zipWith` provides elegant recursive definitions'),'2026-02-05 02:48:05');
