INSERT INTO ir_patterns VALUES(1170,'convert-clojure-scala','clojure','scala','tool','','**FS2**','Streaming',0,NULL,NULL,'Functional streams (replaces core.async)','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1171,'convert-clojure-scala','clojure','scala','idiom','type','nil → Option Type','',0,NULL,NULL,unistr('- Clojure `nil` → Scala `None` (explicit absence)\u000a- Clojure `when-let` → Scala `.map()` combinator\u000a- Clojure `if-let` with default → Scala `.getOrElse()`\u000a- Pattern matching is more idiomatic in Scala than if/else chains\u000a- Compiler enforces handling of both Some and None cases'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1172,'convert-clojure-scala','clojure','scala','idiom','data-structure','Maps → Case Classes','',0,NULL,NULL,unistr('- Clojure maps → Scala case classes for structured data\u000a- Keyword access `:key` → Field access `.field`\u000a- Clojure `assoc` → Scala `.copy()` method\u000a- Case classes provide:\u000a  - Compile-time field checking\u000a  - Pattern matching support\u000a  - Automatic `equals`, `hashCode`, `toString`\u000a  - Better IDE support and refactoring'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1173,'convert-clojure-scala','clojure','scala','idiom','concurrency','Threading Macros → Method Chaining','',0,NULL,NULL,unistr('- Clojure `->>` (thread-last) → Scala method chaining (data flows left-to-right)\u000a- Clojure `->` (thread-first) → Scala `.copy()` chaining for updates\u000a- Scala for-comprehensions are alternative for complex filter/map chains\u000a- Method chaining is more natural in Scala due to OOP foundation\u000a- Both styles maintain immutability'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1174,'convert-clojure-scala','clojure','scala','idiom','data-structure','Multimethods → Pattern Matching / Type Classes','',0,NULL,NULL,unistr('- Clojure multimethods → Scala sealed traits + pattern matching (type-safe dispatch)\u000a- Clojure `:type` key → Scala case class type (compiler-checked)\u000a- Pattern matching exhaustiveness checked at compile time\u000a- Alternative: polymorphic methods for OOP-style dispatch\u000a- Sealed traits ensure all cases are known at compile time'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1175,'convert-clojure-scala','clojure','scala','idiom','memory','Atoms → AtomicReference / Ref','',0,NULL,NULL,unistr('- Clojure `atom` → Scala `AtomicReference` for thread-safe mutable state\u000a- Clojure `swap!` → Scala `.updateAndGet()`\u000a- Clojure `reset!` → Scala `.set()`\u000a- Clojure `@atom` → Scala `.get()`\u000a- For functional effects, use Cats Effect `Ref[IO]`\u000a- Validation can be added through wrapper methods'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1176,'convert-clojure-scala','clojure','scala','idiom','concurrency','core.async Channels → Akka Streams / FS2','',0,NULL,NULL,unistr('- Clojure core.async channels → Akka Streams for back-pressure and complex flows\u000a- Clojure go blocks → Scala Futures or FS2 streams\u000a- Akka Streams provide more structure and operators\u000a- FS2 integrates with Cats Effect for pure FP\u000a- Choose based on complexity: Futures (simple), Akka (complex), FS2 (pure FP)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1177,'convert-clojure-scala','clojure','scala','idiom','function','Macros → Inline Methods / Compile-Time','',0,NULL,NULL,unistr('- Clojure macros → Scala inline methods (Scala 3) for simple cases\u000a- Complex metaprogramming → Scala 3 macros (quote/splice)\u000a- By-name parameters `=> A` for lazy evaluation (similar to macro delay)\u000a- Extension methods for DSL-like syntax\u000a- Scala macros are more restrictive but type-safe\u000a- Prefer higher-order functions over macros when possible'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1178,'convert-clojure-scala','clojure','scala','idiom','type','Protocols → Traits','',0,NULL,NULL,unistr('- Clojure protocols → Scala traits (interfaces with implementations)\u000a- Clojure `defrecord` with protocol → Scala case class extending trait\u000a- Clojure `extend-type` → Scala extension methods or implicit classes\u000a- Scala traits support default implementations\u000a- Extension methods don''t require wrapper types\u000a- Traits can have type parameters and self-types'),'2026-02-05 02:48:05');
