INSERT INTO ir_patterns VALUES(1280,'convert-cpp-rust','cpp','rust','guideline','','Adopt target idioms','',0,NULL,NULL,'Don''t write "C++ code in Rust syntax" (avoid unnecessary Rc/Arc)','2026-02-05 02:48:05');
