INSERT INTO ir_patterns VALUES(1284,'convert-cpp-rust','cpp','rust','negative','','Overusing Rc/Arc (Avoid C++ shared_ptr Mindset)',unistr('Prefer borrowing or single ownership:\u000a\u000a```rust\u000a// Good: Use Box for owned children\u000astruct Node {\u000a    value: i32,\u000a    children: Vec<Box<Node>>,\u000a}\u000a\u000a// Or borrow when possible\u000afn process_nodes(nodes: &[Node]) {\u000a    // Work with borrowed references\u000a}\u000a```'),0,NULL,NULL,unistr('Translating every `shared_ptr` to `Rc`/`Arc`.\u000a\u000a```rust\u000a// Bad: Unnecessary shared ownership\u000ause std::rc::Rc;\u000a\u000astruct Node {\u000a    value: i32,\u000a    children: Vec<Rc<Node>>,  // Over-engineered\u000a}\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1285,'convert-cpp-rust','cpp','rust','tool','','`cxx` crate','Safe C++/Rust FFI',0,NULL,NULL,'Recommended for gradual migration','2026-02-05 02:48:05');
