INSERT INTO ir_patterns VALUES(1292,'convert-cpp-rust','cpp','rust','tool','','`clippy`','Linter',0,NULL,NULL,'Suggests idiomatic Rust patterns','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1293,'convert-cpp-rust','cpp','rust','idiom','general','RAII and Resource Management','',0,NULL,NULL,unistr('- Rust''s `Drop` trait is analogous to C++ destructors for RAII\u000a- Constructors that can fail use `Result<T, E>` instead of exceptions\u000a- Move semantics are default in Rust (no need for `std::move`)\u000a- Ownership system eliminates need for manual delete copy constructors\u000a- The `?` operator propagates errors ergonomically'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1294,'convert-cpp-rust','cpp','rust','idiom','memory','Smart Pointers and Ownership','',0,NULL,NULL,unistr('- Rust prefers single ownership (`Box`) over shared ownership (`Rc`/`Arc`)\u000a- `Option<Box<T>>` replaces nullable pointers\u000a- `.take()` method moves ownership out of an Option, replacing with None\u000a- Shared ownership (Rc/Arc) should be used sparingly in Rust\u000a- Reference counting happens at compile-time via ownership tracking, not runtime'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1295,'convert-cpp-rust','cpp','rust','idiom','type','Templates vs Generics','',0,NULL,NULL,unistr('- Rust generics require explicit trait bounds (e.g., `T: Clone`)\u000a- `where` clause provides cleaner syntax for complex bounds\u000a- Rust''s iterator pattern is more idiomatic than manual collection\u000a- Generic functions use trait bounds instead of template parameter concepts\u000a- No implicit constraints like C++ templates (explicit is better)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1296,'convert-cpp-rust','cpp','rust','idiom','type','Inheritance vs Composition + Traits','',0,NULL,NULL,unistr('- Rust uses traits instead of inheritance for polymorphism\u000a- `dyn Trait` provides runtime polymorphism (like C++ virtual functions)\u000a- Generic bounds provide zero-cost compile-time polymorphism\u000a- No inheritance hierarchy - composition and traits are preferred\u000a- Trait objects require explicit `Box<dyn Trait>` or `&dyn Trait`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1297,'convert-cpp-rust','cpp','rust','idiom','error','Exception Handling to Result Types','',0,NULL,NULL,unistr('- Rust uses `Result<T, E>` instead of exceptions for recoverable errors\u000a- The `?` operator replaces `try/catch` for error propagation\u000a- `From` trait enables automatic error conversion (like exception hierarchies)\u000a- Pattern matching on Result is explicit and type-safe\u000a- Unrecoverable errors use `panic!()` instead of exceptions'),'2026-02-05 02:48:05');
