INSERT INTO ir_patterns VALUES(1398,'convert-elixir-elm','elixir','elm','idiom','error','Tagged Tuples → Result','',0,NULL,NULL,unistr('- Elixir''s `{:ok, value}` / `{:error, reason}` pattern maps directly to Elm''s `Result error value`\u000a- Guards in Elixir (`when b != 0`) become if-expressions in Elm\u000a- Atoms like `:division_by_zero` become strings or custom types\u000a- Both use pattern matching in case expressions'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1399,'convert-elixir-elm','elixir','elm','idiom','general','Nil Handling → Maybe','',0,NULL,NULL,unistr('- Elixir''s `nil` becomes Elm''s `Nothing`\u000a- Present values become `Just value`\u000a- `Maybe.withDefault` replaces nil coalescing\u000a- Pattern matching translates directly'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1400,'convert-elixir-elm','elixir','elm','idiom','data-structure','Enum Operations → List Functions','',0,NULL,NULL,unistr('- `Enum.filter` → `List.filter`\u000a- `Enum.map` → `List.map`\u000a- `Enum.reduce` → `List.foldl` (or `List.foldr`)\u000a- Pipeline operator `|>` is identical\u000a- Capture operator `&()` becomes lambda `\\x ->`\u000a- `rem` becomes `modBy` in Elm'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1401,'convert-elixir-elm','elixir','elm','idiom','data-structure','Pattern Matching Lists','',0,NULL,NULL,unistr('- List pattern matching syntax is nearly identical\u000a- `[head | tail]` in Elixir → `head :: tail` in Elm\u000a- Multiple function clauses become case branches\u000a- Guards can become if-expressions inside branches'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1402,'convert-elixir-elm','elixir','elm','idiom','error','With Statement → Nested Case or Result.andThen','',0,NULL,NULL,unistr('- Elixir''s `with` chains `{:ok, _}` results\u000a- Elm uses `Result.andThen` for equivalent chaining\u000a- Early error returns are handled by Result''s short-circuiting\u000a- Pipeline style preserves readability'),'2026-02-05 02:48:05');
