INSERT INTO ir_patterns VALUES(1499,'convert-elixir-erlang','elixir','erlang','negative','','String vs Binary Confusion',unistr('Always translate Elixir `"strings"` to Erlang binaries `<<"strings">>`.\u000a\u000a---'),0,NULL,NULL,unistr('Elixir strings are UTF-8 binaries; Erlang strings are charlists.\u000a\u000a```elixir\u000a# Elixir\u000aname = "Alice"  # Binary: <<"Alice">>\u000acharlist = ''Alice''  # List: [65, 108, 105, 99, 101]\u000a```\u000a\u000a```erlang\u000a% Erlang\u000aName = <<"Alice">>.  % Binary (Elixir string equivalent)\u000aCharlist = "Alice".  % List (Erlang string, Elixir charlist equivalent)\u000a```'),'2026-02-05 02:48:05');
