INSERT INTO ir_patterns VALUES(1597,'convert-elixir-fsharp','elixir','fsharp','idiom','general','Pipe Operator (Direct Translation)','',0,NULL,NULL,unistr('- Both languages use `|>` for left-to-right function chaining\u000a- F# and Elixir share functional pipeline philosophy\u000a- Minor differences in standard library function names'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1598,'convert-elixir-fsharp','elixir','fsharp','idiom','data-structure','Pattern Matching on Tagged Tuples','',0,NULL,NULL,unistr('- Elixir''s `{:ok, value}` / `{:error, reason}` maps directly to F#''s `Result<''T, ''E>`\u000a- Pattern matching syntax is similar in both languages\u000a- F# requires explicit error type definition'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1599,'convert-elixir-fsharp','elixir','fsharp','idiom','error','with Statement → Result Computation Expression','',0,NULL,NULL,unistr('- Elixir''s `with` statement is railway-oriented programming\u000a- F# computation expressions provide the same short-circuiting behavior\u000a- `let!` in F# unwraps Result like `<-` unwraps tuples in Elixir'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1600,'convert-elixir-fsharp','elixir','fsharp','idiom','general','GenServer → MailboxProcessor','',0,NULL,NULL,unistr('- Both GenServer and MailboxProcessor implement the actor pattern\u000a- F# uses discriminated unions for message types (typed vs Elixir''s atoms)\u000a- `AsyncReplyChannel` in F# replaces Elixir''s `from` parameter for synchronous calls\u000a- Recursive `loop` function maintains state like Elixir''s callback chain'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1601,'convert-elixir-fsharp','elixir','fsharp','idiom','data-structure','Enum Functions → List/Seq Functions','',0,NULL,NULL,unistr('- Elixir `Enum` → F# `List` for eager evaluation\u000a- Elixir `Stream` → F# `Seq` for lazy evaluation\u000a- Function names are similar: `map`, `filter`, `reduce`/`fold`\u000a- Both languages use pipe operator idiomatically'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(1602,'convert-elixir-fsharp','elixir','fsharp','idiom','data-structure','Structs → Records','',0,NULL,NULL,unistr('- Elixir structs and F# records are both immutable by default\u000a- Copy-and-update syntax is similar: `%{user | ...}` vs `{ user with ... }`\u000a- F# records have structural equality automatically (like Elixir structs)'),'2026-02-05 02:48:05');
