INSERT INTO ir_patterns VALUES(2017,'convert-elixir-scala','elixir','scala','negative','','Dynamic Typing → Static Typing',unistr('Use sealed trait ADT for type safety.\u000a\u000a```scala\u000asealed trait Data\u000acase class IntData(value: Int) extends Data\u000acase class StringData(value: String) extends Data\u000acase class ListData[A](values: List[A]) extends Data\u000a\u000adef process(data: Data): Int = data match {\u000a  case IntData(x) => x * 2\u000a  case StringData(x) => x.length\u000a  case ListData(xs) => xs.length\u000a}\u000a```\u000a\u000a---'),0,NULL,NULL,unistr('Elixir allows dynamic typing; Scala requires explicit types.\u000a\u000a```elixir\u000a# Elixir - dynamic\u000adef process(data) do\u000a  case data do\u000a    x when is_integer(x) -> x * 2\u000a    x when is_binary(x) -> String.length(x)\u000a    x when is_list(x) -> length(x)\u000a  end\u000aend\u000a```'),'2026-02-05 02:48:05');
