INSERT INTO ir_patterns VALUES(2095,'convert-elm-erlang','elm','erlang','guideline','','Map to OTP behaviors','',0,NULL,NULL,'Model → gen_server state, Msg → messages, update → handle_call/cast','2026-02-05 02:48:05');
