INSERT INTO ir_patterns VALUES(2098,'convert-elm-erlang','elm','erlang','guideline','','Handle guarantees','',0,NULL,NULL,'Elm''s no-runtime-errors → Erlang''s let-it-crash','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2099,'convert-elm-erlang','elm','erlang','guideline','','Test equivalence','',0,NULL,NULL,'Property-based testing for both languages','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2100,'convert-elm-erlang','elm','erlang','negative','','Assuming Compile-Time Safety','Use dialyzer for static analysis, embrace let-it-crash philosophy with supervision.',0,NULL,NULL,unistr('Elm catches all errors at compile time; Erlang relies on runtime checks and supervision.\u000a\u000a**Elm:**\u000a```elm\u000a-- Compiler forces you to handle all cases\u000aprocessResult : Result Error Value -> String\u000aprocessResult result =\u000a    case result of\u000a        Ok value -> "Success"\u000a        Err error -> "Failed"  -- MUST handle or won''t compile\u000a```\u000a\u000a**Erlang:**\u000a```erlang\u000a% No compile-time exhaustiveness checking\u000aprocess_result({ok, _Value}) -> "Success".\u000a% Forgot {error, _} case → runtime crash (but supervisor restarts)\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2101,'convert-elm-erlang','elm','erlang','tool','','`rebar3`','Build tool',0,NULL,NULL,'Like Elm''s build system','2026-02-05 02:48:05');
