INSERT INTO ir_patterns VALUES(2105,'convert-elm-erlang','elm','erlang','tool','','`eunit`','Unit testing',0,NULL,NULL,'Like elm-test','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2106,'convert-elm-erlang','elm','erlang','tool','','`common_test`','Integration testing',0,NULL,NULL,'Full test suites','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2107,'convert-elm-erlang','elm','erlang','tool','','`proper`','Property-based testing',0,NULL,NULL,'Like elm-explorations/test','2026-02-05 02:48:05');
