INSERT INTO ir_patterns VALUES(2109,'convert-elm-erlang','elm','erlang','tool','','`hackney` / `gun`','HTTP client',0,NULL,NULL,'Like elm/http','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2110,'convert-elm-erlang','elm','erlang','idiom','general','The Elm Architecture → gen_server','',0,NULL,NULL,unistr('- Elm''s Model → gen_server state record\u000a- Elm''s Msg type → message patterns in handle_cast/handle_call\u000a- Elm''s update function → handle_cast/handle_call callbacks\u000a- Elm''s init → gen_server init/1 callback\u000a- gen_server provides supervision, hot code reloading, and OTP integration'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2111,'convert-elm-erlang','elm','erlang','idiom','error','Maybe/Result → Tagged Tuples','',0,NULL,NULL,unistr('- `Nothing` → `{error, Reason}` or `undefined`\u000a- `Just value` → `{ok, Value}`\u000a- Erlang convention: `{ok, Result}` for success, `{error, Reason}` for failure\u000a- Pattern matching in case or function clauses replaces Maybe combinators'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2112,'convert-elm-erlang','elm','erlang','idiom','data-structure','List Operations','',0,NULL,NULL,unistr('- Elm''s pipeline `|>` → nested function calls or list comprehensions\u000a- List comprehensions are more idiomatic in Erlang for filter+map\u000a- `lists:` module provides functional primitives'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2113,'convert-elm-erlang','elm','erlang','idiom','data-structure','Record Updates','',0,NULL,NULL,unistr('- Elm records → Erlang records (compile-time) or maps (runtime)\u000a- Records provide type checking with dialyzer\u000a- Maps are more flexible but less type-safe'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2114,'convert-elm-erlang','elm','erlang','idiom','general','Cmd → Process Operations','',0,NULL,NULL,unistr('- Elm''s Cmd → spawn/spawn_link + message passing\u000a- HTTP in Elm runtime → explicit httpc or third-party libraries (hackney, gun)\u000a- Elm''s managed effects → Erlang''s explicit process control\u000a- Error handling moves from Result type to message patterns'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2115,'convert-elm-erlang','elm','erlang','idiom','general','Sub → Timers and Receives','',0,NULL,NULL,unistr('- Elm''s Time.every → timer:send_interval\u000a- Sub message → handle_info callback\u000a- Cleanup handled in terminate/2'),'2026-02-05 02:48:05');
