INSERT INTO ir_patterns VALUES(2209,'convert-elm-fsharp','elm','fsharp','idiom','general','Maybe/Option Handling','',0,NULL,NULL,unistr('- `Maybe` → `option` is a direct semantic mapping\u000a- `Just` → `Some`, `Nothing` → `None`\u000a- `Maybe.withDefault` → `Option.defaultValue`\u000a- `List.head : List a -> Maybe a` → `List.tryFind` or `List.tryHead`\u000a- F# has richer `Option` module with more combinators'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2210,'convert-elm-fsharp','elm','fsharp','idiom','error','Result/Error Handling','',0,NULL,NULL,unistr('- `Result error value` (Elm) → `Result<''value, ''error>` (F#) - **note reversed type parameters**\u000a- `Ok`/`Err` → `Ok`/`Error`\u000a- `Result.andThen` → `Result.bind`\u000a- F# uses `TryParse` pattern for parsing (returns tuple `bool * value`)\u000a- Both support railway-oriented programming with bind/map'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2211,'convert-elm-fsharp','elm','fsharp','idiom','control-flow','Union Types and Pattern Matching','',0,NULL,NULL,unistr('- Discriminated unions are nearly identical\u000a- Elm: `Type arg` → F#: `Type of arg`\u000a- Record update syntax: `{ model | field = value }` → `{ model with Field = value }`\u000a- Pattern matching syntax is nearly identical\u000a- F# requires explicit `of` keyword for union cases with data'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2212,'convert-elm-fsharp','elm','fsharp','idiom','data-structure','List Operations','',0,NULL,NULL,unistr('- List syntax nearly identical: `[ items ]`\u000a- Function composition: `>>` in both languages\u000a- `List.foldl` → `List.fold` (F# fold is left-associative by default)\u000a- F# has more list functions (`List.sumBy`, `List.groupBy`, etc.)\u000a- Record access: `.field` → `(fun r -> r.Field)` or use lambda'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2213,'convert-elm-fsharp','elm','fsharp','idiom','general','The Elm Architecture (TEA) → F# Elmish','',0,NULL,NULL,unistr('- Elmish is F#''s implementation of The Elm Architecture\u000a- Model, Msg, init, update, view pattern is identical\u000a- `Cmd` type is similar but uses F# async under the hood\u000a- View function receives `dispatch` explicitly in F#\u000a- `Html msg` → `ReactElement` (via Fable.React)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2214,'convert-elm-fsharp','elm','fsharp','idiom','general','JSON Decoding','',0,NULL,NULL,unistr('- F# offers two approaches: attribute-based (simpler) or decoder-based (like Elm)\u000a- Thoth.Json provides Elm-style decoders for F#\u000a- System.Text.Json uses attributes and reflection\u000a- `Maybe` fields → `option` with proper serialization handling\u000a- F# has more serialization libraries available (.NET ecosystem)'),'2026-02-05 02:48:05');
