INSERT INTO ir_patterns VALUES(2276,'convert-elm-haskell','elm','haskell','negative','','Assuming Elm''s Simplicity Limits Apply',unistr('- Use type classes for polymorphism (Eq, Show, Functor, etc.)\u000a- Leverage lazy evaluation (but beware space leaks)\u000a- Use advanced type system features when beneficial (GADTs, type families)'),0,NULL,NULL,'Elm intentionally limits features (no type classes, no laziness control). Haskell has these features.','2026-02-05 02:48:05');
