INSERT INTO ir_patterns VALUES(2281,'convert-elm-haskell','elm','haskell','idiom','general','Maybe Handling','',0,NULL,NULL,unistr('- Maybe is identical in both languages\u000a- Elm''s `Maybe.withDefault` = Haskell''s `fromMaybe`\u000a- Elm''s `.field` accessor becomes Haskell function `field`\u000a- Pattern matching syntax is nearly identical'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2282,'convert-elm-haskell','elm','haskell','idiom','error','Result/Either Error Handling','',0,NULL,NULL,unistr('- `Result err ok` maps to `Either err ok` (note: Left = error, Right = success)\u000a- Elm''s `Result.andThen` = Haskell''s `>>=` (monadic bind)\u000a- Haskell''s do-notation is more concise for chaining\u000a- Both support applicative style for independent validations'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2283,'convert-elm-haskell','elm','haskell','idiom','data-structure','List Operations','',0,NULL,NULL,unistr('- List operations are nearly identical\u000a- Elm''s `|>` pipeline = Haskell''s `&` (from Data.Function) or `$` (right-associative)\u000a- Function composition (`.`) is more idiomatic in Haskell\u000a- List comprehensions more common in Haskell than Elm'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2284,'convert-elm-haskell','elm','haskell','idiom','control-flow','Pattern Matching and Case Expressions','',0,NULL,NULL,unistr('- Pattern matching is nearly identical\u000a- Haskell allows pattern matching in function definitions (more concise)\u000a- Syntax differences: `x :: xs` (Elm) vs `(x:xs)` (Haskell)\u000a- Both support guards and nested patterns'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2285,'convert-elm-haskell','elm','haskell','idiom','data-structure','Record Updates','',0,NULL,NULL,unistr('- Record update syntax is nearly identical\u000a- Haskell requires parentheses for field access: `age user` vs Elm''s `user.age`\u000a- Both create new values (immutability)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2286,'convert-elm-haskell','elm','haskell','idiom','data-structure','Custom Types and Constructors','',0,NULL,NULL,unistr('- Syntax is identical\u000a- Haskell allows deriving type classes (Show, Eq, Functor, etc.)\u000a- Elm auto-derives equality; Haskell requires explicit `deriving Eq`'),'2026-02-05 02:48:05');
