INSERT INTO ir_patterns VALUES(2746,'convert-erlang-roc','erlang','roc','idiom','function','Simple Function Conversion','',0,NULL,NULL,unistr('- Erlang modules become Roc interfaces\u000a- Exported functions go in `exposes`\u000a- Type signatures are inferred but can be explicit\u000a- Function definitions use lambda syntax'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2747,'convert-erlang-roc','erlang','roc','idiom','data-structure','Pattern Matching on Tagged Tuples','',0,NULL,NULL,unistr('- Erlang tagged tuples map to Roc tags\u000a- Pattern matching syntax is similar\u000a- Tag unions make all cases explicit\u000a- Type system ensures exhaustiveness'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2748,'convert-erlang-roc','erlang','roc','idiom','data-structure','List Processing','',0,NULL,NULL,unistr('- Roc provides built-in list functions\u000a- `List.walk` is fold/reduce\u000a- Explicit recursion not needed for common operations\u000a- Higher-order functions are idiomatic'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2749,'convert-erlang-roc','erlang','roc','idiom','data-structure','Records to Records','',0,NULL,NULL,unistr('- Erlang records map directly to Roc records\u000a- Record update syntax is similar (`#record{}` vs `{ record & }`)\u000a- Pattern matching on records works similarly\u000a- Roc records are structural, not nominal'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2750,'convert-erlang-roc','erlang','roc','idiom','function','gen_server State Machine → Pure State Functions','',0,NULL,NULL,unistr('- gen_server becomes pure state functions\u000a- No process lifecycle - just data transformation\u000a- State is explicit parameter and return value\u000a- Effects would be handled by platform, not shown here\u000a- Platform provides concurrency if needed'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2751,'convert-erlang-roc','erlang','roc','idiom','error','Error Handling with Result','',0,NULL,NULL,unistr('- Erlang error tuples map to Roc Result type\u000a- Pattern matching on Result works like case\u000a- Result combinators (`withDefault`) are idiomatic\u000a- Compile-time exhaustiveness checking'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2752,'convert-erlang-roc','erlang','roc','idiom','general','Optional Values','',0,NULL,NULL,unistr('- Erlang `undefined` maps to tag union with None\u000a- `false` from failed search becomes None\u000a- Pattern matching on option types is explicit\u000a- Type system prevents forgetting to handle None case'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(2753,'convert-erlang-roc','erlang','roc','idiom','data-structure','List Comprehensions','',0,NULL,NULL,unistr('- Comprehensions become map/filter operations\u000a- Nested comprehensions use `joinMap` (flatMap)\u000a- More verbose but explicit\u000a- Type signatures make intent clear'),'2026-02-05 02:48:05');
