INSERT INTO ir_patterns VALUES(2893,'convert-fsharp-haskell','fsharp','haskell','negative','','Confusing Either Direction','',0,NULL,NULL,unistr('F#''s Result has Ok/Error, Haskell''s Either has Left/Right\u000a\u000a```haskell\u000a-- WRONG: Thinking Right is error\u000avalidate x = if x > 0 then Left x else Right "Error"\u000a\u000a-- CORRECT: Right is success, Left is error\u000avalidate x = if x > 0 then Right x else Left "Error"\u000a```\u000a\u000a**Fix:** Remember: "Right is right (correct)"'),'2026-02-05 02:48:05');
