INSERT INTO ir_patterns VALUES(3026,'convert-fsharp-roc','fsharp','roc','idiom','general','Option Handling','',0,NULL,NULL,unistr('- F# has built-in `Option<''a>` type; Roc uses tag unions `[Some a, None]`\u000a- F# has `Option.map`; Roc uses pattern matching with `when`\u000a- Both are structural sum types under the hood'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3027,'convert-fsharp-roc','fsharp','roc','idiom','error','Result for Error Handling','',0,NULL,NULL,unistr('- F# has computation expressions (`result { ... }`); Roc uses try operator (`!`)\u000a- F# `Error "msg"` uses strings; Roc `Err(DivByZero)` uses typed tags\u000a- Both propagate errors up the call stack'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3028,'convert-fsharp-roc','fsharp','roc','idiom','data-structure','List Operations','',0,NULL,NULL,unistr('- F# `filter` → Roc `keepIf` (more descriptive name)\u000a- F# `sum` → Roc `walk(0, Num.add)` (explicit fold)\u000a- Both use pipeline operator (`|>`) idiomatically'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3029,'convert-fsharp-roc','fsharp','roc','idiom','control-flow','Pattern Matching','',0,NULL,NULL,unistr('- F# discriminated unions → Roc tag unions (nearly identical)\u000a- F# `match` → Roc `when` (same exhaustiveness checking)\u000a- F# interpolation `$"{x}"` → Roc interpolation `\\(x)` (different syntax)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3030,'convert-fsharp-roc','fsharp','roc','idiom','data-structure','Record Updates','',0,NULL,NULL,unistr('- F# uses `with` keyword; Roc uses `&` operator\u000a- Both create new records (copy-on-write)\u000a- F# uses PascalCase by convention; Roc uses camelCase'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3031,'convert-fsharp-roc','fsharp','roc','idiom','general','Pipeline Composition','',0,NULL,NULL,unistr('- F# has both `>>` (forward composition) and `|>` (pipeline)\u000a- Roc only has `|>` (pipeline) - prefer this style\u000a- Same left-to-right data flow'),'2026-02-05 02:48:05');
