INSERT INTO ir_patterns VALUES(3207,'convert-fsharp-scala','fsharp','scala','negative','','PascalCase vs camelCase','',0,NULL,NULL,unistr('F# uses PascalCase for everything, Scala uses camelCase for members.\u000a\u000a```fsharp\u000a// F# style\u000atype Person = {\u000a    FirstName: string\u000a    LastName: string\u000a}\u000a\u000alet GetFullName person = $"{person.FirstName} {person.LastName}"\u000a```\u000a\u000a**Fix:** Follow Scala conventions\u000a\u000a```scala\u000a// Scala style\u000acase class Person(\u000a  firstName: String,  // camelCase\u000a  lastName: String\u000a)\u000a\u000adef getFullName(person: Person): String = s"${person.firstName} ${person.lastName}"\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3208,'convert-fsharp-scala','fsharp','scala','tool','','.NET CLI (`dotnet`)','sbt',0,NULL,NULL,'Primary build tool','2026-02-05 02:48:05');
