INSERT INTO ir_patterns VALUES(3213,'convert-fsharp-scala','fsharp','scala','idiom','data-structure','Records to Case Classes','',0,NULL,NULL,unistr('- Case classes provide automatic `copy`, `equals`, `hashCode`, `toString`\u000a- Scala uses camelCase for field names (F# uses PascalCase)\u000a- Copy-and-update syntax is similar: `with` in F#, `copy` in Scala\u000a- String interpolation: F# uses `$""`, Scala uses `s""`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3214,'convert-fsharp-scala','fsharp','scala','idiom','type','Discriminated Unions to Sealed Traits','',0,NULL,NULL,unistr('- Sealed traits ensure exhaustive pattern matching like F# discriminated unions\u000a- Case objects for parameterless variants\u000a- Case classes for variants with data\u000a- Pattern matching syntax is similar but Scala uses `match`/`case`\u000a- Compiler enforces exhaustiveness in both languages'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3215,'convert-fsharp-scala','fsharp','scala','idiom','type','Option Type Handling','',0,NULL,NULL,unistr('- Both have built-in Option types with Some/None\u000a- F# uses `Option.map`, Scala uses `.map` (method)\u000a- F# `Option.defaultValue` → Scala `.getOrElse`\u000a- F# pipe `|>` → Scala method chaining `.`\u000a- Pattern matching syntax nearly identical'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3216,'convert-fsharp-scala','fsharp','scala','idiom','error','Result Type to Either','',0,NULL,NULL,unistr('- F# Result → Scala Either (right-biased in Scala 2.12+)\u000a- F# `Ok` → Scala `Right`, F# `Error` → Scala `Left`\u000a- F# `Result.bind` → Scala `.flatMap`\u000a- F# `Result.map` → Scala `.map`\u000a- For-comprehensions replace chained bind/map calls'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3217,'convert-fsharp-scala','fsharp','scala','idiom','concurrency','Async Workflows to Futures','',0,NULL,NULL,unistr('- F# `async { }` → Scala `Future { }` or `IO { }`\u000a- F# `do!` → Scala `_<-` in for-comprehension\u000a- F# `let!` → Scala `x <-` in for-comprehension\u000a- F# `Async.Parallel` → Scala `Future.sequence` or `traverse`\u000a- F# `Async.RunSynchronously` → Scala `Await.result` (Future) or `unsafeRunSync()` (IO)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3218,'convert-fsharp-scala','fsharp','scala','idiom','general','Computation Expressions to For-Comprehensions','',0,NULL,NULL,unistr('- F# computation expressions → Scala for-comprehensions\u000a- F# `let!` → Scala `<-` (bind/flatMap)\u000a- F# `return` → Scala `yield` (map)\u000a- Both desugar to flatMap/map chains\u000a- Scala for-comprehensions work with any type that has flatMap/map'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3219,'convert-fsharp-scala','fsharp','scala','idiom','control-flow','Pattern Matching with Guards','',0,NULL,NULL,unistr('- F# `when` guards → Scala `if` guards\u000a- F# `[]` → Scala `Nil`\u000a- F# `x :: xs` → Scala `x :: xs` (same cons operator)\u000a- Both support deep pattern matching\u000a- Scala enforces exhaustiveness on sealed types'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3220,'convert-fsharp-scala','fsharp','scala','idiom','concurrency','Active Patterns to Custom Extractors','',0,NULL,NULL,unistr('- F# active patterns → Scala custom extractors (`unapply`)\u000a- F# parameterless active patterns → Scala objects with `unapply`\u000a- F# partial active patterns returning `Option` → Scala `unapply` returning `Option`\u000a- Both enable extensible pattern matching\u000a- Scala extractors are more verbose but more flexible'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3221,'convert-fsharp-scala','fsharp','scala','idiom','type','Units of Measure to Tagged Types','',0,NULL,NULL,unistr('- F# units of measure have no direct Scala equivalent\u000a- Scala 2: Use tagged types (shapeless) or value classes\u000a- Scala 3: Opaque types provide zero-cost abstraction\u000a- F# provides compile-time dimension checking, Scala only type checking\u000a- Trade-off: F# has better unit inference, Scala requires more manual work'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3222,'convert-fsharp-scala','fsharp','scala','idiom','type','Type Providers to Code Generation','',0,NULL,NULL,unistr('- F# type providers have no direct Scala equivalent\u000a- Scala alternatives:\u000a  1. **Manual case classes** - most common, explicit\u000a  2. **Runtime JSON libraries** - circe, play-json, upickle\u000a  3. **Code generation plugins** - sbt plugins for OpenAPI, Protobuf, etc.\u000a  4. **Scala 3 macros** - can achieve similar results but more complex\u000a- F# advantage: compile-time type safety from external data sources\u000a- Scala advantage: more explicit, easier to debug, better tooling support'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3223,'convert-fsharp-scala','fsharp','scala','error','','`Option<''T>`','`Option[T]`',0,NULL,NULL,'Value may be absent','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3224,'convert-fsharp-scala','fsharp','scala','error','','`Result<''T,''E>`','`Either[E, T]`',0,NULL,NULL,'Typed errors (preferred)','2026-02-05 02:48:05');
