INSERT INTO ir_patterns VALUES(3315,'convert-golang-rust','golang','rust','negative','','Trying to Return Borrowed References Without Lifetimes',unistr('```rust\u000a// Return owned value instead:\u000afn get_data() -> Data {\u000a    Data::new()\u000a}\u000a\u000a// Or use Box for heap allocation:\u000afn get_data() -> Box<Data> {\u000a    Box::new(Data::new())\u000a}\u000a```'),0,NULL,NULL,unistr('```rust\u000a// Go allows this easily:\u000a// func getData() *Data {\u000a//     d := Data{}\u000a//     return &d  // GC keeps this alive\u000a// }\u000a\u000a// Rust compile error:\u000afn get_data() -> &Data {\u000a    let d = Data::new();\u000a    &d  // Error: returns reference to local variable\u000a}\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3316,'convert-golang-rust','golang','rust','tool','','`c2rust`','C to Rust transpiler',0,NULL,NULL,'Produces unsafe Rust, needs manual cleanup','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3317,'convert-golang-rust','golang','rust','tool','','`go2rs`','Experimental Go→Rust',0,NULL,NULL,'Very limited, not production-ready','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3318,'convert-golang-rust','golang','rust','tool','','Manual translation','Most reliable',0,NULL,NULL,'Use this skill as guide','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3319,'convert-golang-rust','golang','rust','idiom','error','Error Handling with Multiple Returns','',0,NULL,NULL,unistr('- Rust''s `Result<T, E>` encodes success/failure in the type system\u000a- The `?` operator propagates errors ergonomically\u000a- Error wrapping uses `map_err` instead of manual checks\u000a- Borrowed `&Path` instead of owned `String` for efficiency'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3320,'convert-golang-rust','golang','rust','idiom','general','Nil Checking','',0,NULL,NULL,unistr('- `Option<T>` makes nullability explicit in the type system\u000a- Combinators like `and_then` and `unwrap_or` are idiomatic\u000a- Pattern matching with guards is more readable\u000a- Borrowed references avoid unnecessary cloning'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3321,'convert-golang-rust','golang','rust','idiom','type','Interface Implementation','',0,NULL,NULL,unistr('- Rust traits are explicitly implemented with `impl Trait for Type`\u000a- Generic functions use trait bounds (`<R: Reader>`)\u000a- Mutable borrows (`&mut`) make mutation explicit\u000a- The `?` operator replaces verbose error checking'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3322,'convert-golang-rust','golang','rust','idiom','concurrency','Goroutines and Channels','',0,NULL,NULL,unistr('- Tokio''s async/await is more explicit about async boundaries\u000a- `task::spawn` creates async tasks similar to goroutines\u000a- Awaiting task handles is more type-safe than channels\u000a- Move semantics avoid accidental captures\u000a- Alternative: Use channels with `tokio::sync::mpsc` for Go-like patterns'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3323,'convert-golang-rust','golang','rust','idiom','general','Defer for Cleanup','',0,NULL,NULL,unistr('- Rust''s RAII (Drop trait) automatically cleans up resources\u000a- No need for explicit `defer` statements\u000a- Scope-based cleanup is deterministic\u000a- More type-safe than runtime defer'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3324,'convert-golang-rust','golang','rust','idiom','control-flow','Type Assertions and Type Switches','',0,NULL,NULL,unistr('- Rust enums are type-safe alternatives to `interface{}`\u000a- Pattern matching exhaustively handles all variants\u000a- Compiler ensures all cases are covered\u000a- Avoid `Any` downcasting when possible (use enums instead)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3325,'convert-golang-rust','golang','rust','idiom','memory','Method Receivers (Value vs Pointer)','',0,NULL,NULL,unistr('- Rust makes mutability explicit: `&self`, `&mut self`, `self`\u000a- Borrowing prevents accidental copies\u000a- Consuming methods (`self`) transfer ownership\u000a- More explicit control over mutation'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3326,'convert-golang-rust','golang','rust','idiom','data-structure','Struct Embedding (Composition)','',0,NULL,NULL,unistr('- Rust favors explicit composition over embedding\u000a- No automatic method promotion (use delegation)\u000a- `Deref` trait can provide field access convenience\u000a- More explicit about the relationship'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3327,'convert-golang-rust','golang','rust','idiom','general','Context Propagation','',0,NULL,NULL,unistr('- Rust doesn''t have built-in context; use timeout or cancellation tokens\u000a- `tokio::select!` provides cancellation semantics\u000a- Explicit timeout durations instead of context deadlines\u000a- More type-safe cancellation handling'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3328,'convert-golang-rust','golang','rust','idiom','function','Variadic Functions','',0,NULL,NULL,unistr('- Rust doesn''t have variadic functions; use slices\u000a- Macros can provide variadic-like syntax\u000a- Iterator methods are more idiomatic than loops\u000a- More explicit about allocation'),'2026-02-05 02:48:05');
