INSERT INTO ir_patterns VALUES(3549,'convert-haskell-scala','haskell','scala','negative','','Assuming Lazy Evaluation','Use `LazyList` for potentially infinite sequences, `lazy val` for deferred computation.',0,NULL,NULL,unistr('Expecting Scala to be lazy like Haskell.\u000a\u000a**Example:**\u000a```scala\u000a// ❌ This will hang in Scala (strict evaluation)\u000aval naturals = (1 to Int.MaxValue).toList  // Tries to build entire list!\u000a\u000a// ✓ Use LazyList for infinite sequences\u000aval naturals = LazyList.from(1)\u000a```'),'2026-02-05 02:48:05');
