INSERT INTO ir_patterns VALUES(3558,'convert-haskell-scala','haskell','scala','idiom','general','Maybe/Option Handling','',0,NULL,NULL,unistr('- `Maybe` and `Option` are semantically equivalent\u000a- Both use pattern matching for explicit handling\u000a- Scala''s `.getOrElse` is more concise than `fromMaybe`\u000a- Method chaining is idiomatic in Scala'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3559,'convert-haskell-scala','haskell','scala','idiom','error','Either for Error Handling','',0,NULL,NULL,unistr('- Both use Either with Left for errors, Right for success\u000a- Haskell''s `do-notation` maps to Scala''s `for-comprehension`\u000a- ADT error types work similarly in both languages\u000a- Scala requires explicit `yield` at the end of for-comprehension'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3560,'convert-haskell-scala','haskell','scala','idiom','data-structure','List Comprehensions','',0,NULL,NULL,unistr('- Both desugar to map/flatMap/filter\u000a- Scala''s for-comprehension requires `yield` keyword\u000a- Guards (filters) use `if` in both\u000a- Scala often prefers method chaining for simple transformations'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3561,'convert-haskell-scala','haskell','scala','idiom','control-flow','Pattern Matching on ADTs','',0,NULL,NULL,unistr('- Haskell uses data constructors, Scala uses case classes\u000a- Pattern matching syntax is similar\u000a- Guards use `if` in Scala match, `|` in Haskell function definitions\u000a- `sealed trait` ensures exhaustiveness checking like Haskell'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3562,'convert-haskell-scala','haskell','scala','idiom','data-structure','Type Classes to Implicits/Given','',0,NULL,NULL,unistr('- Type classes map to traits with implicit/given instances\u000a- Constraints become implicit/using parameters\u000a- Scala 3 syntax is closer to Haskell''s\u000a- Both support type class derivation (Haskell with deriving, Scala with macros)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3563,'convert-haskell-scala','haskell','scala','idiom','general','Lazy Evaluation','',0,NULL,NULL,unistr('- Haskell is lazy by default, Scala is strict by default\u000a- Use `LazyList` for infinite sequences\u000a- Use `lazy val` for deferred computation\u000a- By-name parameters (`=> A`) for lazy function arguments\u000a- Scala 2.13+ renamed Stream to LazyList'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3564,'convert-haskell-scala','haskell','scala','idiom','function','Function Composition and Application','',0,NULL,NULL,unistr('- Haskell''s `.` maps to `compose` (right-to-left) or `andThen` (left-to-right)\u000a- Scala prefers method chaining over function composition\u000a- Haskell''s `$` isn''t needed in Scala (no precedence issues)\u000a- Point-free style less common in Scala'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3565,'convert-haskell-scala','haskell','scala','idiom','general','Monadic Composition','',0,NULL,NULL,unistr('- Haskell''s `do-notation` maps directly to Scala''s `for-comprehension`\u000a- Both desugar to flatMap/map\u000a- Haskell uses `return`, Scala uses `yield`\u000a- `guard` becomes `if` in for-comprehension\u000a- IO monad requires Cats Effect library in Scala'),'2026-02-05 02:48:05');
