INSERT INTO ir_patterns VALUES(3709,'convert-java-c','java','c','idiom','data-structure','Object Creation and Destruction','',0,NULL,NULL,unistr('- Java handles memory automatically with GC; C requires manual `malloc`/`free`\u000a- Opaque pointers hide implementation details (similar to Java private fields)\u000a- Constructor/destructor pattern mimics Java''s object lifecycle\u000a- Always check `malloc` return for NULL (Java throws OutOfMemoryError)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3710,'convert-java-c','java','c','idiom','general','Null Handling','',0,NULL,NULL,unistr('- C has no built-in Optional type; must check NULL explicitly\u000a- Manual memory management: know when to free returned pointers\u000a- C strings are mutable; modifications require copying'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3711,'convert-java-c','java','c','idiom','error','Exception Handling → Error Codes','',0,NULL,NULL,unistr('- C has no exceptions; use return codes and `errno`\u000a- `errno` is a thread-local global for system error details\u000a- Check every I/O operation return value\u000a- Manual resource cleanup (no try-with-resources)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3712,'convert-java-c','java','c','idiom','memory','Interfaces → Function Pointer Vtables','',0,NULL,NULL,unistr('- C has no built-in polymorphism; simulate with function pointer tables (vtables)\u000a- `void *impl` stores the concrete type (requires casting)\u000a- Vtable stores function pointers for interface methods\u000a- Manual vtable initialization (Java does this automatically)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3713,'convert-java-c','java','c','idiom','data-structure','ArrayList → Dynamic Array','',0,NULL,NULL,unistr('- Java ArrayList auto-grows; C requires manual `realloc`\u000a- Track both `size` (current elements) and `capacity` (allocated space)\u000a- Manual bounds checking (Java throws IndexOutOfBoundsException)\u000a- Explicit destroy function to free memory'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3714,'convert-java-c','java','c','idiom','data-structure','HashMap → Custom Hash Table','',0,NULL,NULL,unistr('- C has no built-in hash table; use libraries (uthash, glib) or implement manually\u000a- Manual key copying (`strdup`) and freeing\u000a- Return values indicate success/failure (no null to indicate missing)\u000a- Iteration requires library-specific macros'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3715,'convert-java-c','java','c','idiom','general','Synchronized → Mutexes','',0,NULL,NULL,unistr('- Java `synchronized` is automatic; C requires explicit lock/unlock\u000a- Must remember to unlock (Java does this automatically even on exception)\u000a- Consider using atomics (`atomic_int`) for simple counters (C11+)\u000a- Initialize and destroy mutexes explicitly'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3716,'convert-java-c','java','c','idiom','concurrency','Thread Creation','',0,NULL,NULL,unistr('- Java Thread wraps OS threads; C uses POSIX threads directly\u000a- Function pointers instead of lambda/Runnable\u000a- Manual error checking (Java throws exceptions)\u000a- No automatic thread pooling (Java ExecutorService)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3717,'convert-java-cpp','java','cpp','type_mapping','','`List<T>`','`std::vector<T>`',0,NULL,NULL,'Dynamic array','2026-02-05 02:48:05');
