INSERT INTO ir_patterns VALUES(3802,'convert-java-cpp','java','cpp','idiom','general','Getter/Setter → Direct Access or Property','',0,NULL,NULL,unistr('- C++ uses `const` methods for getters (promise not to modify object)\u000a- Return `const&` for large objects to avoid copying\u000a- Throw standard exceptions (`std::invalid_argument`, etc.)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3803,'convert-java-cpp','java','cpp','idiom','memory','Null Handling → Optional/Smart Pointers','',0,NULL,NULL,unistr('- `std::optional` makes null handling explicit (C++17)\u000a- Safer than raw pointers for optional values\u000a- Supports functional-style operations (`transform`, `value_or`)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3804,'convert-java-cpp','java','cpp','idiom','data-structure','Collection Operations → STL Algorithms/Ranges','',0,NULL,NULL,unistr('- C++20 ranges provide lazy evaluation like Java streams\u000a- Traditional STL algorithms are more verbose but work in older C++\u000a- Ranges compose better and are more readable'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3805,'convert-java-cpp','java','cpp','idiom','error','Try-with-Resources → RAII','',0,NULL,NULL,unistr('- C++ uses RAII pattern - resources cleaned up in destructors\u000a- No need for explicit `close()` - automatic when object destroyed\u000a- More general than Java''s try-with-resources'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3806,'convert-java-cpp','java','cpp','idiom','data-structure','Interfaces → Abstract Classes with Pure Virtuals','',0,NULL,NULL,unistr('- Pure virtual functions (`= 0`) = Java abstract methods\u000a- Virtual functions with body = Java default methods\u000a- **Always** provide virtual destructor for polymorphic classes\u000a- Use `override` keyword for safety (C++11)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(3807,'convert-java-cpp','java','cpp','idiom','general','Inheritance → Composition (Preferred in C++)','',0,NULL,NULL,unistr('- Composition is more flexible than inheritance in C++\u000a- Avoids exposing base class interface\u000a- Better encapsulation and type safety'),'2026-02-05 02:48:05');
