INSERT INTO ir_patterns VALUES(4005,'convert-java-rust','java','rust','idiom','general','Null Checking','',0,NULL,NULL,unistr('- `Option<T>` makes nullability explicit in the type system\u000a- No null pointer exceptions possible at runtime\u000a- Combinators like `and_then` and `unwrap_or` are idiomatic\u000a- Pattern matching with guards is more expressive\u000a- Borrowed references avoid unnecessary cloning'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4006,'convert-java-rust','java','rust','idiom','error','Exception Handling','',0,NULL,NULL,unistr('- `Result<T, E>` encodes success/failure in the type system\u000a- The `?` operator propagates errors ergonomically (like Java `throws`)\u000a- Pattern matching makes error handling explicit\u000a- No hidden control flow (exceptions jumping up the stack)\u000a- Errors are values, not exceptional control flow'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4007,'convert-java-rust','java','rust','idiom','general','Optional Chaining','',0,NULL,NULL,unistr('- Direct mapping from Java `Optional` to Rust `Option`\u000a- Rust''s `Option` methods are similar to Java''s\u000a- Pattern matching can destructure nested `Option`s\u000a- Borrowed references avoid cloning'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4008,'convert-java-rust','java','rust','idiom','general','Stream/Iterator Operations','',0,NULL,NULL,unistr('- Rust iterators are zero-cost abstractions (like Java streams)\u000a- Similar combinator API: `filter`, `map`, `collect`, `sum`\u000a- Rust iterators are lazy (like Java streams)\u000a- No need for specialized primitive streams (`mapToInt`, etc.)\u000a- More explicit borrowing with `iter()` vs `into_iter()`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4009,'convert-java-rust','java','rust','idiom','control-flow','Builder Pattern','',0,NULL,NULL,unistr('- Similar builder pattern structure\u000a- Rust uses `self` consumption for method chaining\u000a- No need for nested `Builder` class (separate struct)\u000a- `impl Into<String>` accepts both `String` and `&str`\u000a- More ergonomic with fewer allocations'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4010,'convert-java-rust','java','rust','idiom','type','Interface Implementation','',0,NULL,NULL,unistr('- Rust traits are explicitly implemented with `impl Trait for Type`\u000a- Generic functions use trait bounds (`<R: Reader>`)\u000a- Mutable borrows (`&mut`) make mutation explicit\u000a- The `?` operator replaces `throws` declarations\u000a- No `@Override` annotation needed (enforced by trait)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4011,'convert-java-rust','java','rust','idiom','general','Inheritance vs Composition','',0,NULL,NULL,unistr('- Rust favors composition over inheritance\u000a- Traits define shared behavior without state\u000a- No virtual method dispatch overhead by default\u000a- More flexible than rigid class hierarchies\u000a- Prefer trait bounds over inheritance for polymorphism'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4012,'convert-java-rust','java','rust','idiom','concurrency','Static Methods and Factory Patterns','',0,NULL,NULL,unistr('- Rust uses associated functions instead of static methods\u000a- No `static` keyword needed (no `self` parameter)\u000a- Factory methods return `Result` for validation\u000a- Named constructors are idiomatic (`new`, `with_capacity`, etc.)\u000a- Private constructors not needed (use `pub` selectively)'),'2026-02-05 02:48:05');
