INSERT INTO ir_patterns VALUES(4197,'convert-objc-swift','objc','swift','guideline','','Test equivalence','',0,NULL,NULL,'Same inputs → same outputs','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4198,'convert-objc-swift','objc','swift','negative','','Force Unwrapping Optionals','',0,NULL,NULL,unistr('Crashes when value is nil\u000a\u000a**Objective-C:**\u000a```objc\u000a// Nil messaging is safe\u000aNSString *name = [user name];  // Returns nil if user is nil\u000aNSString *upper = [name uppercaseString];  // Returns nil if name is nil\u000a```\u000a\u000a**Swift (bad):**\u000a```swift\u000alet name = user!.name  // Crashes if user is nil\u000alet upper = name!.uppercased()  // Crashes if name is nil\u000a```\u000a\u000a**Swift (good):**\u000a```swift\u000aguard let user = user else { return }\u000alet name = user.name\u000alet upper = name?.uppercased() ?? ""\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4199,'convert-objc-swift','objc','swift','tool','','Xcode migration assistant','Automated Swift conversion',0,NULL,NULL,'Use as starting point, manual refinement needed','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4200,'convert-objc-swift','objc','swift','tool','','`swiftc`','Swift compiler',0,NULL,NULL,'Compiles Swift code','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4201,'convert-objc-swift','objc','swift','tool','','Swift REPL','Interactive Swift',0,NULL,NULL,'`swift` command in terminal','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4202,'convert-objc-swift','objc','swift','tool','','`swift-demangle`','Demangle Swift symbols',0,NULL,NULL,'Debug symbol names','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4203,'convert-objc-swift','objc','swift','tool','','SwiftLint','Swift style linter',0,NULL,NULL,'Enforce Swift conventions','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4204,'convert-objc-swift','objc','swift','tool','','Objective-C → Swift converter (Xcode)','Edit → Convert → To Modern Objective-C Syntax first',0,NULL,NULL,'Improves conversion quality','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4205,'convert-objc-swift','objc','swift','idiom','general','Property Declaration and Access','',0,NULL,NULL,unistr('- Swift properties don''t need `@property` declaration\u000a- Memory semantics: `strong` is default, `weak` explicit, `copy` unnecessary for value types\u000a- Initialization required for all non-optional stored properties\u000a- `let` for immutable, `var` for mutable'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4206,'convert-objc-swift','objc','swift','idiom','function','Method Declaration and Invocation','',0,NULL,NULL,unistr('- Swift methods use parameter labels naturally\u000a- Singleton: `static let` is thread-safe and simpler than dispatch_once\u000a- Completion handlers: prefer `Result<T, E>` over separate parameters\u000a- `@escaping` must be explicit for closures that outlive function scope'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4207,'convert-objc-swift','objc','swift','idiom','general','Nullability and Optional Handling','',0,NULL,NULL,unistr('- Swift optionals are explicit and type-safe\u000a- `if let` / `guard let` for safe unwrapping\u000a- Optional chaining (`?.`) replaces Objective-C nil messaging\u000a- Nil coalescing (`??`) provides defaults\u000a- Force unwrap (`!`) should be rare and justified'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4208,'convert-objc-swift','objc','swift','idiom','type','Protocols and Delegation','',0,NULL,NULL,unistr('- Swift protocols require `AnyObject` for class-only protocols (enables weak references)\u000a- No `@required`/`@optional` - use protocol extensions for default implementations\u000a- No runtime checks needed with type-safe protocols\u000a- `any Protocol` for existential types (heterogeneous collections)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4209,'convert-objc-swift','objc','swift','idiom','general','Enumerations','',0,NULL,NULL,unistr('- `NS_ENUM` → Swift `enum` with raw value\u000a- `NS_OPTIONS` → `OptionSet` struct for bitwise options\u000a- Swift enums are type-safe with pattern matching\u000a- Array literal syntax for option sets'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4210,'convert-objc-swift','objc','swift','idiom','error','Error Handling','',0,NULL,NULL,unistr('- Swift uses exceptions (`throws`) instead of error pointers\u000a- Custom error types conform to `Error` protocol (usually enums)\u000a- `do-catch` for error handling\u000a- `try?` for optional conversion\u000a- `Result<T, E>` for explicit error values\u000a- More type-safe and composable than NSError pattern'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4211,'convert-objc-swift','objc','swift','idiom','general','Categories → Extensions','',0,NULL,NULL,unistr('- Categories directly map to Swift extensions\u000a- Prefer computed properties over methods when no parameters\u000a- Extensions can add stored properties via associated objects (advanced)\u000a- Swift extensions more powerful (can conform to protocols, add constraints)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4212,'convert-objc-swift','objc','swift','idiom','function','Blocks → Closures','',0,NULL,NULL,unistr('- Closure types more concise than block types\u000a- `@escaping` required for stored closures\u000a- Prefer `Result<T, E>` over separate data/error parameters\u000a- Swift async/await preferred over callbacks\u000a- `[weak self]` / `guard let self` pattern cleaner than weak-strong dance'),'2026-02-05 02:48:05');
