INSERT INTO ir_patterns VALUES(4349,'convert-python-clojure','python','clojure','guideline','','Map types first','',0,NULL,NULL,'Python and Clojure are both dynamic but Clojure emphasizes immutability','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4350,'convert-python-clojure','python','clojure','guideline','','Embrace immutability','',0,NULL,NULL,'replace in-place mutations with functional transformations','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4351,'convert-python-clojure','python','clojure','guideline','','Use REPL-driven development','',0,NULL,NULL,'Clojure is designed for interactive development','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4352,'convert-python-clojure','python','clojure','guideline','','Adopt functional idioms','',0,NULL,NULL,'avoid classes, prefer pure functions and data transformations','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4353,'convert-python-clojure','python','clojure','guideline','','Handle edge cases','',0,NULL,NULL,'None→nil, exceptions, mutable state','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4354,'convert-python-clojure','python','clojure','guideline','','Test equivalence','',0,NULL,NULL,'same inputs → same outputs','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4355,'convert-python-clojure','python','clojure','negative','','Mutable State → Immutable Data',unistr('```clojure\u000a;; Rebind with new value\u000a(def items (conj items 4))  ; Now items is [1 2 3 4]\u000a\u000a;; Or use atoms for mutable state\u000a(def items (atom [1 2 3]))\u000a(swap! items conj 4)\u000a(println @items)  ; [1 2 3 4]\u000a\u000a;; Or work with local bindings\u000a(let [items [1 2 3]\u000a      items (conj items 4)\u000a      items (conj items 5)]\u000a  (println items))  ; [1 2 3 4 5]\u000a```'),0,NULL,NULL,unistr('```clojure\u000a;; Python: in-place mutation\u000a# items.append(value)\u000a# items[0] = new_value\u000a\u000a;; Clojure: trying to mutate\u000a(def items [1 2 3])\u000a(conj items 4)  ; Returns new vector, doesn''t modify items!\u000a(println items)  ; Still [1 2 3]\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4356,'convert-python-clojure','python','clojure','tool','','Manual translation','Full control',0,NULL,NULL,'Recommended for production','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4357,'convert-python-clojure','python','clojure','tool','','REPL experimentation','Interactive development',0,NULL,NULL,'Core Clojure workflow','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4358,'convert-python-clojure','python','clojure','tool','','`clj-python`','Python-Clojure interop',0,NULL,NULL,'Call Python from Clojure (libpython-clj)','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4359,'convert-python-clojure','python','clojure','idiom','data-structure','List Comprehensions → Sequence Operations','',0,NULL,NULL,unistr('- Python list comprehensions are eager; Clojure `for` is lazy (more efficient)\u000a- Clojure''s threading macros (`->>`) make pipelines clearer\u000a- `reduce` is idiomatic for aggregation'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4360,'convert-python-clojure','python','clojure','idiom','data-structure','Dictionary Operations → Map Operations','',0,NULL,NULL,unistr('- Clojure maps are immutable; use `assoc`, `update`, `merge` for "changes"\u000a- Keywords (`:timeout`) are idiomatic for map keys\u000a- `into` + `map` is the comprehension pattern for maps'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4361,'convert-python-clojure','python','clojure','idiom','data-structure','Classes → Records and Maps','',0,NULL,NULL,unistr('- Clojure separates data from behavior (functions operate on data structures)\u000a- `defrecord` provides type identity and performance benefits\u000a- Plain maps are often simpler and more flexible than records\u000a- Functions are defined separately, not as methods'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4362,'convert-python-clojure','python','clojure','idiom','control-flow','Iteration → Sequence Operations','',0,NULL,NULL,unistr('- Clojure favors pure transformations over imperative loops\u000a- `filter`, `map`, `reduce` are core sequence operations\u000a- `doseq` is for side effects (like printing), `for` is for lazy sequences\u000a- `map-indexed` and `map vector` replace Python''s enumerate and zip'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4363,'convert-python-clojure','python','clojure','idiom','general','None Handling → nil Handling','',0,NULL,NULL,unistr('- Clojure uses `nil` instead of `None`\u000a- `when-let` and `if-let` bind and test in one step\u000a- `some->` and `some->>` short-circuit on `nil` (like optional chaining)\u000a- `or` returns first truthy value (like Python''s `or`)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4364,'convert-python-clojure','python','clojure','idiom','error','Exceptions → Explicit Error Handling','',0,NULL,NULL,unistr('- Clojure uses exceptions for truly exceptional cases\u000a- For expected errors, return maps with `:ok` / `:error` keys (or use a library like `cats` for Either)\u000a- `with-open` ensures resource cleanup (like Python''s context managers)\u000a- `ex-info` creates exceptions with data maps'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4365,'convert-python-clojure','python','clojure','idiom','function','Decorators → Macros or Higher-Order Functions','',0,NULL,NULL,unistr('- Python decorators → Clojure higher-order functions or macros\u000a- Macros run at compile time, can transform syntax\u000a- Clojure has no property syntax; use plain functions\u000a- `defmacro` for code transformation, `defn` for runtime wrapping'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4366,'convert-python-clojure','python','clojure','idiom','function','Object-Oriented → Functional','',0,NULL,NULL,unistr('- Clojure prefers immutable data + pure functions over mutable objects\u000a- `->` threading macro passes result through function chain\u000a- For necessary state, use atoms (`swap!` for updates, `@` for reads)\u000a- Separate data (maps) from behavior (functions)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4367,'convert-python-clojure','python','clojure','idiom','general','String Formatting → str and format','',0,NULL,NULL,unistr('- `str` concatenates arguments (simple, idiomatic)\u000a- `format` uses Java''s `String.format` (printf-style)\u000a- `cl-format` (Common Lisp format) for advanced formatting'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4368,'convert-python-clojure','python','clojure','idiom','concurrency','Async/Await → core.async','',0,NULL,NULL,unistr('- Python''s async/await → Clojure''s `go` blocks and channels\u000a- `<!` takes from channel (inside `go`), `<!!` blocks (outside `go`)\u000a- `>!` puts onto channel, `>!!` blocks\u000a- Different paradigm: CSP (channels) vs promises/futures'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4369,'convert-python-clojure','python','clojure','error','','`raise Exception("msg")`','`(throw (Exception. "msg"))`',0,NULL,NULL,'Direct exception','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4370,'convert-python-clojure','python','clojure','error','','`raise ValueError(...)`','`(throw (ex-info "msg" {:data ...}))`',0,NULL,NULL,'Exception with data','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4371,'convert-python-clojure','python','clojure','error','','`try: ... except E: ...`','`(try ... (catch E e ...))`',0,NULL,NULL,'Catching exceptions','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4372,'convert-python-clojure','python','clojure','error','','`try: ... finally: ...`','`(try ... (finally ...))`',0,NULL,NULL,'Cleanup block','2026-02-05 02:48:05');
