INSERT INTO ir_patterns VALUES(4827,'convert-python-erlang','python','erlang','guideline','','Preserve semantics','',0,NULL,NULL,'over syntax similarity','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4828,'convert-python-erlang','python','erlang','guideline','','Adopt Erlang idioms','',0,NULL,NULL,'don''t write "Python code in Erlang syntax"','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4829,'convert-python-erlang','python','erlang','guideline','','Think in processes','',0,NULL,NULL,'replace threads/async with lightweight processes','2026-02-05 02:48:05');
