INSERT INTO ir_patterns VALUES(4842,'convert-python-erlang','python','erlang','tool','','`ErlPort`','Python interop',0,NULL,NULL,'Call Python from Erlang','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4843,'convert-python-erlang','python','erlang','idiom','control-flow','None Handling (Option Pattern)','',0,NULL,NULL,unistr('- Python uses None/truthy checks; Erlang uses tagged tuples `{ok, Value}` / `error`\u000a- Erlang''s pattern matching is more explicit and compile-time checked\u000a- Tagged tuples are the idiomatic Erlang way to represent optional values'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4844,'convert-python-erlang','python','erlang','idiom','data-structure','List Comprehensions','',0,NULL,NULL,unistr('- Erlang list comprehensions are syntactically similar to Python''s\u000a- Use `||` instead of `for`, guards instead of `if`\u000a- For aggregation, `lists:foldl/3` is the standard approach\u000a- List operations in Erlang are functional transformations'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4845,'convert-python-erlang','python','erlang','idiom','data-structure','Dictionary Operations','',0,NULL,NULL,unistr('- Erlang maps are immutable; operations return new maps\u000a- `maps:get/3` takes default as third parameter\u000a- `maps:map/2` transforms values while preserving keys\u000a- No direct equivalent to setdefault because of immutability'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4846,'convert-python-erlang','python','erlang','idiom','general','String Formatting','',0,NULL,NULL,unistr('- Erlang uses `io_lib:format/2` with format specifiers: `~s` (string), `~p` (any term), `~w` (term), `~.2f` (float)\u000a- Returns an iolist, not a string - flatten or convert to binary\u000a- Binary concatenation is efficient but verbose; use `io_lib:format/2` for readability'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4847,'convert-python-erlang','python','erlang','idiom','general','Duck Typing → Behaviors','',0,NULL,NULL,unistr('- Erlang uses explicit behaviors (`-behaviour(gen_server)`) instead of duck typing\u000a- Behavior modules define callbacks that implementing modules must provide\u000a- Process-based abstraction is more common: send messages, receive responses\u000a- Compile-time checking of behavior implementations'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4848,'convert-python-erlang','python','erlang','idiom','control-flow','Context Managers → Process Lifecycle','',0,NULL,NULL,unistr('- Erlang uses `try...after` for cleanup guarantees (similar to Python''s finally)\u000a- Process-based patterns are common: spawn a process to manage the resource\u000a- Processes can be supervised; if they crash, supervisor handles cleanup\u000a- No __enter__/__exit__ protocol; use explicit try...after blocks'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4849,'convert-python-erlang','python','erlang','idiom','concurrency','Async/Await → Processes and Message Passing','',0,NULL,NULL,unistr('- Python''s async/await creates coroutines; Erlang uses lightweight processes\u000a- Erlang processes are true concurrency primitives (can run on different cores)\u000a- Message passing replaces async callbacks\u000a- No event loop needed - BEAM VM handles scheduling\u000a- Processes are isolated and fault-tolerant'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4850,'convert-python-erlang','python','erlang','idiom','error','Exception Handling → Let It Crash','',0,NULL,NULL,unistr('- Python: defensive programming with try/except everywhere\u000a- Erlang: let processes crash, supervisors restart them\u000a- Errors are expected; design for failure, not defensive coding\u000a- Try/catch only at supervision boundaries or API boundaries\u000a- Supervision trees provide fault isolation and recovery'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4851,'convert-python-erlang','python','erlang','idiom','data-structure','Class Inheritance → Behavior + gen_server','',0,NULL,NULL,unistr('- Erlang has no inheritance; use behaviors for contracts\u000a- Behaviors define callbacks that modules must implement\u000a- For stateful objects, use gen_server (OTP behavior)\u000a- Composition over inheritance is enforced\u000a- Process-based objects can be supervised'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4852,'convert-python-erlang','python','erlang','idiom','function','Decorators → Parse Transforms or Wrapper Functions','',0,NULL,NULL,unistr('- Erlang has no decorators; use explicit wrapper functions\u000a- Parse transforms can modify AST at compile time (advanced, rarely needed)\u000a- Functions are first-class; pass them as arguments for HOF patterns\u000a- Records and maps don''t have methods; use module functions instead'),'2026-02-05 02:48:05');
