INSERT INTO ir_patterns VALUES(4931,'convert-python-fsharp','python','fsharp','idiom','general','None Handling (Optional Chaining)','',0,NULL,NULL,unistr('- Python uses truthiness while F# uses explicit `Option<''T>`\u000a- F# pattern matching is exhaustive (compiler ensures all cases handled)\u000a- Pipe operator `|>` chains operations left-to-right (like UNIX pipes)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4932,'convert-python-fsharp','python','fsharp','idiom','data-structure','List Comprehensions → List/Seq Expressions','',0,NULL,NULL,unistr('- F# has both list expressions (like comprehensions) and pipe chains\u000a- Pipe operator style is more composable and idiomatic\u000a- `Seq<''T>` is lazy (like Python generators), `List<''T>` is eager'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4933,'convert-python-fsharp','python','fsharp','idiom','data-structure','Dictionary/Map Operations','',0,NULL,NULL,unistr('- F# defaults to immutable `Map<''K, ''V>` (functional style)\u000a- Operations return new maps rather than mutating in-place\u000a- Can use .NET `Dictionary` for mutable operations when needed'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4934,'convert-python-fsharp','python','fsharp','idiom','data-structure','Class → Record + Functions','',0,NULL,NULL,unistr('- F# records provide structural equality automatically\u000a- Separating data (record) from functions is more functional\u000a- Member methods available but less idiomatic than standalone functions'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4935,'convert-python-fsharp','python','fsharp','idiom','control-flow','Iteration and Loops → Recursion/Higher-Order Functions','',0,NULL,NULL,unistr('- F# favors recursion and higher-order functions over loops\u000a- Tail recursion is optimized by F# compiler\u000a- `fold`, `map`, `filter` express intent more clearly than loops'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4936,'convert-python-fsharp','python','fsharp','idiom','general','Context Managers → use Binding','',0,NULL,NULL,unistr('- F# `use` binding calls `Dispose()` automatically\u000a- Both Python and F# ensure resource cleanup\u000a- F# leverages .NET''s `IDisposable` pattern'),'2026-02-05 02:48:05');
