INSERT INTO ir_patterns VALUES(4993,'convert-python-golang','python','golang','guideline','','Handle edge cases','',0,NULL,NULL,'None, exceptions, dynamic typing assumptions','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4994,'convert-python-golang','python','golang','guideline','','Test equivalence','',0,NULL,NULL,'same inputs → same outputs','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4995,'convert-python-golang','python','golang','idiom','general','None Handling (Optional Values)','',0,NULL,NULL,unistr('- Python uses `None` with truthiness; Go uses `nil` with explicit pointer checks\u000a- Go''s zero values provide defaults without needing `None` for primitives\u000a- Go pointers are explicit about nullability'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4996,'convert-python-golang','python','golang','idiom','data-structure','List Comprehensions → Slice Loops','',0,NULL,NULL,unistr('- Go doesn''t have list comprehensions; use explicit loops\u000a- `range` loops are idiomatic for iteration\u000a- `append` grows slices dynamically (similar to Python lists)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4997,'convert-python-golang','python','golang','idiom','data-structure','Dictionary Operations','',0,NULL,NULL,unistr('- Go''s two-value map access (`value, ok := map[key]`) checks existence\u000a- No built-in `get` method; use existence check pattern\u000a- Explicit loops replace comprehensions'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4998,'convert-python-golang','python','golang','idiom','general','String Formatting','',0,NULL,NULL,unistr('- Go uses `fmt` package with C-style format specifiers\u000a- `%s` for strings, `%d` for integers, `%v` for default format\u000a- Type-safe at runtime (not compile-time like some languages)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(4999,'convert-python-golang','python','golang','idiom','type','Duck Typing → Interfaces','',0,NULL,NULL,unistr('- Python relies on runtime duck typing; Go uses compile-time interfaces\u000a- Go interfaces are implicit (no "implements" keyword)\u000a- More type-safe but requires upfront interface definition'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5000,'convert-python-golang','python','golang','idiom','general','Context Managers → Defer','',0,NULL,NULL,unistr('- Python''s `with` guarantees cleanup via `__exit__`\u000a- Go''s `defer` schedules function calls for later (LIFO order)\u000a- Both ensure cleanup even with errors/returns'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5001,'convert-python-golang','python','golang','idiom','function','Decorators → Function Wrappers','',0,NULL,NULL,unistr('- Go doesn''t have decorator syntax; use function wrappers\u000a- Requires explicit wrapping instead of `@` syntax\u000a- Type signatures must match exactly (less flexible than Python)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5002,'convert-python-golang','python','golang','idiom','data-structure','Class Methods and Properties','',0,NULL,NULL,unistr('- Go doesn''t have properties; use methods\u000a- No automatic getter/setter generation\u000a- Explicit error returns instead of exceptions'),'2026-02-05 02:48:05');
