INSERT INTO ir_patterns VALUES(5341,'convert-python-roc','python','roc','idiom','general','None/Optional Handling','',0,NULL,NULL,unistr('- Python uses `None` and truthy checks; Roc uses tag unions `[Some a, None]`\u000a- Python allows property access on potentially-None values (runtime error); Roc requires pattern matching (compile-time safety)\u000a- Roc''s exhaustive pattern matching prevents forgetting the None case'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5342,'convert-python-roc','python','roc','idiom','error','Result for Error Handling','',0,NULL,NULL,unistr('- Python uses exceptions; Roc uses Result type (compile-time error handling)\u000a- Python `try/except` → Roc `when ... is` pattern matching\u000a- Roc errors are typed (DivByZero tag, not string), enabling exhaustive checking'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5343,'convert-python-roc','python','roc','idiom','data-structure','List Comprehensions','',0,NULL,NULL,unistr('- Python comprehensions are concise but limited; Roc uses explicit pipeline of operations\u000a- Roc''s `List.keepIf` (filter) + `List.map` composes clearly\u000a- For aggregation, use `List.walk` (fold) instead of built-in `sum`\u000a- Pipeline operator `|>` provides left-to-right data flow like comprehensions'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5344,'convert-python-roc','python','roc','idiom','data-structure','Dictionary Operations','',0,NULL,NULL,unistr('- Python dicts are mutable; Roc dicts are immutable (operations return new dicts)\u000a- Python `dict.get(key, default)` → Roc `Dict.get` returns Result, use `withDefault`\u000a- Dict comprehensions → `Dict.map` for value transformation\u000a- Roc''s functional style makes data flow explicit'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5345,'convert-python-roc','python','roc','idiom','general','String Formatting','',0,NULL,NULL,unistr('- Python f-strings auto-convert to string; Roc requires explicit `Num.toStr` for numbers\u000a- Roc uses `\\(expr)` for interpolation (similar to f-string braces)\u000a- String concatenation is available but interpolation is cleaner'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5346,'convert-python-roc','python','roc','idiom','data-structure','Class → Record + Module Functions','',0,NULL,NULL,unistr('- Python classes combine data and behavior; Roc separates into records (data) and module functions (behavior)\u000a- Python methods mutate `self`; Roc functions return new values (immutability)\u000a- No `self` in Roc - pass the record explicitly as a parameter\u000a- Roc''s approach is more functional: data + pure functions'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5347,'convert-python-roc','python','roc','idiom','concurrency','Async/Await → Task','',0,NULL,NULL,unistr('- Python `async def` → Roc `Task a err` (platform-provided)\u000a- Python `await` → Roc `!` suffix (try operator)\u000a- Python `asyncio.gather` → Roc `Task.sequence` (platform controls parallelism)\u000a- Python needs `asyncio.run`; Roc `main` is already a Task that platform executes\u000a- Roc''s platform model separates pure code from effectful I/O'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5348,'convert-python-roc','python','roc','idiom','error','Context Managers → Try with Cleanup','',0,NULL,NULL,unistr('- Python context managers (`with`) → Roc platforms handle resource cleanup\u000a- Python''s `__enter__`/`__exit__` protocol → No direct equivalent; platform manages resources\u000a- File operations return Task; platform ensures proper cleanup\u000a- For custom resource management, structure as explicit acquisition/release in Task chains'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5349,'convert-python-roc','python','roc','idiom','error','Exception Hierarchy → Tagged Errors','',0,NULL,NULL,unistr('- Python exception hierarchies → Roc tag unions for error types\u000a- Python `raise` → Roc `Err(tag)`\u000a- Python `try/except` with hierarchy → Roc pattern matching on all error variants\u000a- Roc''s exhaustive matching ensures all error cases are handled at compile time'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5350,'convert-python-roc','python','roc','idiom','function','Decorators → Higher-Order Functions','',0,NULL,NULL,unistr('- Python decorators can have side effects anywhere; Roc enforces purity\u000a- For logging with I/O, wrap in Task (not shown above for simplicity)\u000a- For pure transformations, use higher-order functions\u000a- Roc has no built-in decorator syntax; use explicit function composition'),'2026-02-05 02:48:05');
