INSERT INTO ir_patterns VALUES(5524,'convert-python-rust','python','rust','guideline','','Handle arbitrary-precision integers','',0,NULL,NULL,'decide if `i64` is enough or if you need `BigInt`','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5525,'convert-python-rust','python','rust','guideline','','Preserve semantics','',0,NULL,NULL,'over syntax similarity','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5526,'convert-python-rust','python','rust','guideline','','Adopt Rust idioms','',0,NULL,NULL,'don''t write "Python code in Rust syntax"','2026-02-05 02:48:05');
