INSERT INTO ir_patterns VALUES(5528,'convert-python-rust','python','rust','guideline','','Test equivalence','',0,NULL,NULL,'same inputs → same outputs','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5529,'convert-python-rust','python','rust','negative','','Arbitrary Precision Integer Overflow',unistr('```rust\u000a// Use appropriate size or BigInt\u000ause num_bigint::BigInt;\u000ause num_traits::pow::Pow;\u000a\u000alet x = BigInt::from(10).pow(100_u32);  // No overflow\u000a```'),0,NULL,NULL,unistr('```rust\u000a// Python: unlimited integer size\u000a# x = 10 ** 100  # Works fine\u000a\u000a// Rust: fixed-size integers\u000alet x: i32 = 10_i32.pow(100);  // PANIC! Overflow in debug mode\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5530,'convert-python-rust','python','rust','tool','','`py2rs`','Python → Rust transpiler',0,NULL,NULL,'Experimental, limited support','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5531,'convert-python-rust','python','rust','tool','','`PyO3`','Python ↔ Rust FFI',0,NULL,NULL,'Call Rust from Python or vice versa','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5532,'convert-python-rust','python','rust','tool','','`maturin`','Build Python extensions in Rust',0,NULL,NULL,'For keeping Python interface, Rust backend','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5533,'convert-python-rust','python','rust','tool','','Manual translation','Full control',0,NULL,NULL,'Recommended for production code','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5534,'convert-python-rust','python','rust','idiom','general','None Handling (Optional Chaining)','',0,NULL,NULL,unistr('- Python uses truthiness (`if user`) while Rust uses explicit `Option<T>`\u000a- Rust''s combinator methods (`map`, `unwrap_or`) are more explicit about handling the `None` case\u000a- `as_ref()` converts `Option<T>` to `Option<&T>` to avoid consuming the value'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5535,'convert-python-rust','python','rust','idiom','data-structure','List Comprehensions → Iterator Chains','',0,NULL,NULL,unistr('- Python list comprehensions are eager; Rust iterators are lazy (more efficient)\u000a- Rust requires explicit `collect()` to materialize into a collection\u000a- Terminal operations like `sum()` consume the iterator automatically'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5536,'convert-python-rust','python','rust','idiom','data-structure','Dictionary Operations','',0,NULL,NULL,unistr('- Rust''s `entry()` API is more efficient than Python''s `setdefault()` for expensive defaults\u000a- `or_insert_with()` takes a closure, only calling it if the key is missing\u000a- Rust''s iterator `collect()` can build many collection types, including `HashMap`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5537,'convert-python-rust','python','rust','idiom','general','String Formatting','',0,NULL,NULL,unistr('- Rust''s `format!` macro is compile-time checked for type safety\u000a- `{}` is the default placeholder; use `{:?}` for debug output, `{:#?}` for pretty-print\u000a- Rust doesn''t have string interpolation; use macros instead'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5538,'convert-python-rust','python','rust','idiom','type','Duck Typing → Traits','',0,NULL,NULL,unistr('- Python relies on runtime checks (duck typing); Rust checks at compile time\u000a- Rust traits are explicit contracts, catching errors early\u000a- Generic functions in Rust are monomorphized (one compiled version per concrete type)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5539,'convert-python-rust','python','rust','idiom','general','Context Managers → RAII','',0,NULL,NULL,unistr('- Python uses `__enter__` / `__exit__` protocols; Rust uses `Drop` trait\u000a- Rust''s ownership system guarantees cleanup at scope exit (compile-time enforced)\u000a- No need for explicit `with` statement - scope-based cleanup is automatic'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5540,'convert-python-rust','python','rust','idiom','general','Dynamic Attribute Access','',0,NULL,NULL,unistr('- Rust has no runtime reflection for dynamic attribute access\u000a- Use enums for known variants, `HashMap` for truly dynamic data\u000a- Trade runtime flexibility for compile-time safety and performance'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5541,'convert-python-rust','python','rust','idiom','error','Exception Chaining','',0,NULL,NULL,unistr('- Rust doesn''t have exception chaining; use nested error types or libraries like `anyhow`\u000a- `map_err()` transforms errors explicitly\u000a- `?` operator propagates errors up the call stack (like re-raising)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5542,'convert-python-rust','python','rust','idiom','general','Multiple Return Values','',0,NULL,NULL,unistr('- Both languages support tuple returns\u000a- Rust prefers named structs for complex returns (better documentation, field names)\u000a- Rust requires explicit error handling (hence `Result`)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5543,'convert-python-rust','python','rust','idiom','type','Decorators → Macros or Trait Implementations','',0,NULL,NULL,unistr('- Rust has no decorator syntax; use `#[derive(...)]` for common patterns\u000a- Function decorators require manual implementation or crates like `cached`\u000a- Properties are just methods in Rust (no special syntax)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(5544,'convert-python-rust','python','rust','error','','`raise Exception("error")`','`return Err(Error::Message)`',0,NULL,NULL,'Exceptions → Result','2026-02-05 02:48:05');
