INSERT INTO ir_patterns VALUES(5843,'convert-python-typescript','python','typescript','negative','','Python `None` → TypeScript `null` vs `undefined`',unistr('Choose a convention:\u000a- Use `null` for explicit "not found" cases\u000a- Use `undefined` for optional/uninitialized values\u000a- Or stick to one consistently (prefer `undefined` for simplicity)'),0,NULL,NULL,unistr('Python has one "null" value (`None`), TypeScript has two (`null` and `undefined`).\u000a\u000a**Python:**\u000a```python\u000adef find_user(id: str) -> User | None:\u000a    # ...\u000a    return None  # Only one way to represent "no value"\u000a```\u000a\u000a**TypeScript:**\u000a```typescript\u000a// Need to decide: null or undefined?\u000afunction findUser(id: string): User | null {\u000a  return null;  // Explicit absence\u000a}\u000a\u000a// Or\u000afunction findUser(id: string): User | undefined {\u000a  return undefined;  // Implicit absence (default)\u000a}\u000a\u000a// Often both are possible\u000afunction findUser(id: string): User | null | undefined {\u000a  // ...\u000a}\u000a```'),'2026-02-05 02:48:05');
