INSERT INTO ir_patterns VALUES(6003,'convert-roc-scala','roc','scala','idiom','data-structure','Simple Function and Record','',0,NULL,NULL,unistr('- Roc record → Scala case class\u000a- Roc interface (module) → Scala companion object\u000a- String interpolation syntax differs\u000a- Type inference works in both but Scala encourages explicit return types'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6004,'convert-roc-scala','roc','scala','idiom','control-flow','Tag Union with Pattern Matching','',0,NULL,NULL,unistr('- Tag union → Sealed trait + case classes/objects\u000a- `when` → `match`\u000a- Ability constraint → type parameter (toString implicit)\u000a- Exhaustiveness checking works in both'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6005,'convert-roc-scala','roc','scala','idiom','general','Option Handling','',0,NULL,NULL,unistr('- Roc tag union `[Some a, None]` → Scala `Option[A]`\u000a- Nested `when` → for-comprehension (more ergonomic)\u000a- Method chaining `map`/`getOrElse` → similar in Scala\u000a- Scala''s Option is more idiomatic and has richer API'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6006,'convert-roc-scala','roc','scala','idiom','data-structure','List Processing','',0,NULL,NULL,unistr('- `List.map` → `.map` (method syntax)\u000a- `List.keepIf` → `.filter`\u000a- `List.walk` → `.foldLeft`\u000a- Pipeline → method chaining or for-comprehension\u000a- Scala offers multiple equivalent styles'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6007,'convert-roc-scala','roc','scala','idiom','error','Error Handling with Result','',0,NULL,NULL,unistr('- `Result ok err` → `Either[err, ok]` (same order)\u000a- Try operator `!` → for-comprehension for early returns\u000a- Roc''s explicit error tags → Scala''s String or custom types\u000a- `Try` captures exceptions similar to Roc''s result pattern\u000a- `.toOption` converts Result/Either/Try to Option'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6008,'convert-roc-scala','roc','scala','idiom','data-structure','Abilities to Type Classes','',0,NULL,NULL,unistr('- Roc ability → Scala trait (type class)\u000a- Automatic derivation → manual implicit instances\u000a- Ability constraint → implicit parameter\u000a- Roc has fewer abilities but they''re automatic\u000a- Scala requires explicit instances but more flexible'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6009,'convert-roc-scala','roc','scala','idiom','function','Higher-Order Functions and Currying','',0,NULL,NULL,unistr('- Higher-order functions work similarly\u000a- Currying is more natural in Scala (multiple parameter lists)\u000a- Scala has built-in `compose` and `andThen` on functions\u000a- Type signatures use `=>` vs `->`'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6010,'convert-roc-scala','roc','scala','idiom','data-structure','Records with Update','',0,NULL,NULL,unistr('- Roc record update `{ record & ... }` → Scala `copy` method\u000a- Default values can be in constructor directly\u000a- Case class provides `copy` automatically\u000a- Scala''s syntax is more concise'),'2026-02-05 02:48:05');
