INSERT INTO ir_patterns VALUES(6251,'convert-typescript-rust','typescript','rust','guideline','','Analyze source thoroughly','',0,NULL,NULL,'before writing target','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6252,'convert-typescript-rust','typescript','rust','guideline','','Map types first','',0,NULL,NULL,'create type equivalence table','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6253,'convert-typescript-rust','typescript','rust','guideline','','Preserve semantics','',0,NULL,NULL,'over syntax similarity','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6254,'convert-typescript-rust','typescript','rust','guideline','','Adopt Rust idioms','',0,NULL,NULL,'don''t write "TypeScript code in Rust syntax"','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6255,'convert-typescript-rust','typescript','rust','guideline','','Handle edge cases','',0,NULL,NULL,'null/undefined, error paths, resource cleanup','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6256,'convert-typescript-rust','typescript','rust','guideline','','Test equivalence','',0,NULL,NULL,'same inputs → same outputs','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6257,'convert-typescript-rust','typescript','rust','negative','','Over-cloning to Satisfy Borrow Checker','Learn to work with references. Clone only when you truly need owned data.',0,NULL,NULL,unistr('Coming from TypeScript, new Rust developers often clone excessively to avoid borrow checker errors.\u000a\u000a**Example:**\u000a```rust\u000a// ❌ Bad: Cloning everything\u000afn get_full_name_bad(user: &User) -> String {\u000a    let first = user.first_name.clone();\u000a    let last = user.last_name.clone();\u000a    format!("{} {}", first, last)\u000a}\u000a\u000a// ✓ Good: Borrow instead\u000afn get_full_name(user: &User) -> String {\u000a    format!("{} {}", user.first_name, user.last_name)\u000a}\u000a```'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6258,'convert-typescript-rust','typescript','rust','tool','','ts2rs','Experimental',0,NULL,NULL,'Limited scope, not production-ready','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6259,'convert-typescript-rust','typescript','rust','tool','','Manual conversion','Recommended',0,NULL,NULL,'No mature automated tool exists','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6260,'convert-typescript-rust','typescript','rust','idiom','general','Null/Undefined Handling','',0,NULL,NULL,unistr('- TypeScript''s `null` and `undefined` both map to Rust''s `Option<T>`\u000a- Option combinators (`map`, `unwrap_or`) replace optional chaining\u000a- Rust''s borrow checker requires explicit ownership decisions (`&User` vs `User`)'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6261,'convert-typescript-rust','typescript','rust','idiom','data-structure','Array Methods','',0,NULL,NULL,unistr('- Iterator adaptors are zero-cost abstractions in Rust\u000a- `.iter()` creates a borrowed iterator (doesn''t consume the collection)\u000a- `.sum()` is specialized and more efficient than manual reduce\u000a- Type annotation may be needed for `sum()` to infer the result type'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6262,'convert-typescript-rust','typescript','rust','idiom','data-structure','Object Destructuring','',0,NULL,NULL,unistr('- Rust supports struct destructuring but not rest patterns\u000a- Use `..` to ignore remaining fields\u000a- For true "rest" behavior, manually construct a new struct'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6263,'convert-typescript-rust','typescript','rust','idiom','general','Default Parameters','',0,NULL,NULL,unistr('- Rust doesn''t have default parameters\u000a- Use `Option<T>` to make parameters optional\u000a- Use `Default` trait for complex types with sensible defaults\u000a- Consider multiple function variants for different arities'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6264,'convert-typescript-rust','typescript','rust','idiom','general','Template Literals','',0,NULL,NULL,unistr('- `format!` macro provides type-safe string formatting\u000a- Display trait must be implemented for custom types\u000a- More verbose but catches type errors at compile time'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6265,'convert-typescript-rust','typescript','rust','idiom','general','Object Literals','',0,NULL,NULL,unistr('- Rust separates data (struct) from behavior (impl)\u000a- Methods require explicit `self` parameter\u000a- No implicit `this` binding'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6266,'convert-typescript-rust','typescript','rust','idiom','data-structure','Class Inheritance → Composition','',0,NULL,NULL,unistr('- Rust uses composition over inheritance\u000a- Traits define shared behavior\u000a- Structs can contain other structs for data sharing\u000a- Delegation requires explicit methods'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6267,'convert-typescript-rust','typescript','rust','idiom','control-flow','Method Chaining with Builder Pattern','',0,NULL,NULL,unistr('- Builder pattern is idiomatic in both languages\u000a- Rust builders consume `self` and return `Self` for chaining\u000a- Final `build()` consumes the builder'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6268,'convert-typescript-rust','typescript','rust','idiom','concurrency','Async Iteration','',0,NULL,NULL,unistr('- Rust uses Stream from futures crate for async iteration\u000a- `stream::unfold` creates stateful streams\u000a- `while let Some(...)` pattern for consuming streams'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6269,'convert-typescript-rust','typescript','rust','idiom','module','Namespace/Module Organization','',0,NULL,NULL,unistr('- Rust modules are file-based or inline\u000a- `pub` keyword controls visibility\u000a- `use` statements import items into scope'),'2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6270,'convert-typescript-rust','typescript','rust','error','','`throw new Error()`','`return Err(...)`',0,NULL,NULL,'Recoverable errors','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6271,'convert-typescript-rust','typescript','rust','error','','`try/catch`','`result?`',0,NULL,NULL,'Error propagation','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6272,'convert-typescript-rust','typescript','rust','error','','Uncaught exception','`panic!()`',0,NULL,NULL,'Unrecoverable errors','2026-02-05 02:48:05');
INSERT INTO ir_patterns VALUES(6273,'convert-typescript-rust','typescript','rust','error','','`finally`','Drop trait',0,NULL,NULL,'Resource cleanup','2026-02-05 02:48:05');
