INSERT INTO semantic_gaps VALUES(1,4,4,'structural','c → cpp','Forgetting to Use `nullptr` Instead of `NULL`','medium','','none',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(2,4,4,'structural','c → rust','Use-After-Free','medium','','none',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(3,NULL,1,'structural','clojure → elm','Assuming Dynamic Typing','medium',unistr('Treating Elm like dynamically-typed Clojure\u000a\u000a```elm\u000a-- ❌ WRONG: Can''t have heterogeneous lists\u000ausers = [ { name = "Alice" }, { name = "Bob", age = 30 } ]\u000a-- ERROR: Record fields must match\u000a\u000a-- ✓ CORRECT: Define explicit type with Maybe for optional fields\u000atype alias User =\u000a    { name : String\u000a    , age : Maybe Int\u000a    }\u000a\u000ausers =\u000a    [ { name = "Alice", age = Nothing }\u000a    , { name = "Bob", age = Just 30 }\u000a    ]\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(4,NULL,2,'structural','clojure → erlang','Atom Table Exhaustion','medium','','none',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(5,NULL,1,'structural','clojure → haskell','Dynamic Type Assumptions → Static Type Requirements','medium',unistr('Clojure allows heterogeneous collections; Haskell requires homogeneous types.\u000a\u000a```clojure\u000a;; Clojure: Mixed types OK\u000a(def mixed [1 "two" :three 4.0])\u000a```\u000a\u000a```haskell\u000a-- Haskell: Need sum type for mixed\u000adata Value\u000a    = IntVal Int\u000a    | StringVal String\u000a    | KeywordVal String\u000a    | DoubleVal Double\u000a\u000amixed :: [Value]\u000amixed = [IntVal 1, StringVal "two", KeywordVal "three", DoubleVal 4.0]\u000a```\u000a\u000a**Fix:** Use algebraic data types (ADTs) to represent variants.'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(6,4,4,'structural','cpp → rust','Overusing Rc/Arc (Avoid C++ shared_ptr Mindset)','medium',unistr('Prefer borrowing or single ownership:\u000a\u000a```rust\u000a// Good: Use Box for owned children\u000astruct Node {\u000a    value: i32,\u000a    children: Vec<Box<Node>>,\u000a}\u000a\u000a// Or borrow when possible\u000afn process_nodes(nodes: &[Node]) {\u000a    // Work with borrowed references\u000a}\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(7,2,1,'structural','elixir → elm','Expecting Runtime Dynamism','medium','','none',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(8,2,2,'structural','elixir → erlang','String vs Binary Confusion','medium',unistr('Always translate Elixir `"strings"` to Erlang binaries `<<"strings">>`.\u000a\u000a---'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(9,2,1,'structural','elixir → roc','Process-Based Thinking in Pure Code','medium',unistr('```roc\u000a# ✓ Use explicit state passing\u000aState : I64\u000a\u000aincrement : State -> State\u000aincrement = \\count -> count + 1\u000a\u000a# State is passed explicitly, not hidden in process\u000a# Platform provides state management if needed\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(10,2,1,'structural','elixir → scala','Dynamic Typing → Static Typing','medium',unistr('Use sealed trait ADT for type safety.\u000a\u000a```scala\u000asealed trait Data\u000acase class IntData(value: Int) extends Data\u000acase class StringData(value: String) extends Data\u000acase class ListData[A](values: List[A]) extends Data\u000a\u000adef process(data: Data): Int = data match {\u000a  case IntData(x) => x * 2\u000a  case StringData(x) => x.length\u000a  case ListData(xs) => xs.length\u000a}\u000a```\u000a\u000a---'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(11,1,2,'structural','elm → erlang','Assuming Compile-Time Safety','medium','Use dialyzer for static analysis, embrace let-it-crash philosophy with supervision.','partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(12,1,1,'structural','elm → haskell','Assuming Elm''s Simplicity Limits Apply','medium',unistr('- Use type classes for polymorphism (Eq, Show, Functor, etc.)\u000a- Leverage lazy evaluation (but beware space leaks)\u000a- Use advanced type system features when beneficial (GADTs, type families)'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(13,2,1,'structural','erlang → haskell','Forgetting Type Signatures','medium',unistr(': Always write top-level type signatures.\u000a\u000a```haskell\u000a-- Bad: Type defaulting may surprise you\u000adivide x y = x / y\u000a\u000a-- Good: Explicit constraints\u000adivide :: Double -> Double -> Double\u000adivide x y = x / y\u000a```\u000a\u000a---'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(14,1,1,'structural','fsharp → haskell','Confusing Either Direction','medium',unistr('F#''s Result has Ok/Error, Haskell''s Either has Left/Right\u000a\u000a```haskell\u000a-- WRONG: Thinking Right is error\u000avalidate x = if x > 0 then Left x else Right "Error"\u000a\u000a-- CORRECT: Right is success, Left is error\u000avalidate x = if x > 0 then Right x else Left "Error"\u000a```\u000a\u000a**Fix:** Remember: "Right is right (correct)"'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(15,1,1,'structural','fsharp → scala','PascalCase vs camelCase','medium',unistr('F# uses PascalCase for everything, Scala uses camelCase for members.\u000a\u000a```fsharp\u000a// F# style\u000atype Person = {\u000a    FirstName: string\u000a    LastName: string\u000a}\u000a\u000alet GetFullName person = $"{person.FirstName} {person.LastName}"\u000a```\u000a\u000a**Fix:** Follow Scala conventions\u000a\u000a```scala\u000a// Scala style\u000acase class Person(\u000a  firstName: String,  // camelCase\u000a  lastName: String\u000a)\u000a\u000adef getFullName(person: Person): String = s"${person.firstName} ${person.lastName}"\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(16,4,4,'structural','golang → rust','Trying to Return Borrowed References Without Lifetimes','medium',unistr('```rust\u000a// Return owned value instead:\u000afn get_data() -> Data {\u000a    Data::new()\u000a}\u000a\u000a// Or use Box for heap allocation:\u000afn get_data() -> Box<Data> {\u000a    Box::new(Data::new())\u000a}\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(17,1,1,'structural','haskell → roc','Lazy vs Strict - Infinite Lists','medium',unistr('Direct translation of lazy infinite structures\u000a\u000a```haskell\u000a-- Haskell: Works fine\u000anaturals = [0..]\u000aevens = filter even naturals\u000a```\u000a\u000a```roc\u000a# Roc: Would hang forever!\u000a# naturals = List.range { start: At 0, end: At maxI64 }  # Too large\u000a# evens = List.keepIf naturals Num.isEven  # Never completes\u000a```\u000a\u000a**Fix:** Use finite ranges or iterators\u000a```roc\u000a# Generate finite range\u000anaturals = List.range { start: At 0, end: Before 1000 }\u000aevens = List.keepIf naturals Num.isEven\u000a\u000a# Or use stream/iterator pattern (if platform provides)\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(18,1,1,'structural','haskell → scala','Assuming Lazy Evaluation','medium','Use `LazyList` for potentially infinite sequences, `lazy val` for deferred computation.','partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(19,NULL,4,'structural','java → cpp','Object Slicing','medium',unistr('```cpp\u000aclass Base {\u000apublic:\u000a    virtual void print() { std::cout << "Base\\n"; }\u000a};\u000a\u000aclass Derived : public Base {\u000a    int extra;\u000apublic:\u000a    void print() override { std::cout << "Derived\\n"; }\u000a};\u000a\u000avoid process(Base obj) {  // Takes by value - SLICING!\u000a    obj.print();  // Always prints "Base"\u000a}\u000a\u000aDerived d;\u000aprocess(d);  // Derived object sliced to Base\u000a```\u000a\u000a**Fix:**\u000a```cpp\u000avoid process(const Base& obj) {  // Take by reference\u000a    obj.print();  // Polymorphic behavior\u000a}\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(20,NULL,NULL,'structural','objc → swift','Force Unwrapping Optionals','medium',unistr('Crashes when value is nil\u000a\u000a**Objective-C:**\u000a```objc\u000a// Nil messaging is safe\u000aNSString *name = [user name];  // Returns nil if user is nil\u000aNSString *upper = [name uppercaseString];  // Returns nil if name is nil\u000a```\u000a\u000a**Swift (bad):**\u000a```swift\u000alet name = user!.name  // Crashes if user is nil\u000alet upper = name!.uppercased()  // Crashes if name is nil\u000a```\u000a\u000a**Swift (good):**\u000a```swift\u000aguard let user = user else { return }\u000alet name = user.name\u000alet upper = name?.uppercased() ?? ""\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(21,6,NULL,'structural','python → clojure','Mutable State → Immutable Data','medium',unistr('```clojure\u000a;; Rebind with new value\u000a(def items (conj items 4))  ; Now items is [1 2 3 4]\u000a\u000a;; Or use atoms for mutable state\u000a(def items (atom [1 2 3]))\u000a(swap! items conj 4)\u000a(println @items)  ; [1 2 3 4]\u000a\u000a;; Or work with local bindings\u000a(let [items [1 2 3]\u000a      items (conj items 4)\u000a      items (conj items 5)]\u000a  (println items))  ; [1 2 3 4 5]\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(22,6,2,'structural','python → elixir','Expecting Mutable State','medium','','none',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(23,6,1,'structural','python → haskell','Forgetting About Laziness','medium',unistr('```haskell\u000aimport Control.DeepSeq (force)\u000a\u000a-- Force strict evaluation when needed\u000aprocessData :: [Int] -> [Int]\u000aprocessData items = force results\u000a  where\u000a    results = map expensiveFunc items\u000a\u000a-- Or use strict versions\u000aimport qualified Data.Map.Strict as M\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
INSERT INTO semantic_gaps VALUES(24,6,4,'structural','python → rust','Arbitrary Precision Integer Overflow','medium',unistr('```rust\u000a// Use appropriate size or BigInt\u000ause num_bigint::BigInt;\u000ause num_traits::pow::Pow;\u000a\u000alet x = BigInt::from(10).pow(100_u32);  // No overflow\u000a```'),'partial',NULL,'2026-02-05 02:48:05');
