INSERT INTO decision_points VALUES(1,'DP-001: Type Annotation Strategy','How to handle missing type information','["infer_all", "annotate_public", "annotate_all", "use_any"]','Prefer annotate_public for maintainability',NULL);
INSERT INTO decision_points VALUES(2,'DP-002: Generic Constraints','How to add generic bounds','["minimal_bounds", "maximal_bounds", "infer_bounds"]','Start with minimal bounds, add as needed',NULL);
INSERT INTO decision_points VALUES(3,'DP-003: HKT Elimination','Strategy for removing higher-kinded types','["defunctionalize", "monomorphize", "use_trait_objects"]','Defunctionalize preserves more type safety',NULL);
INSERT INTO decision_points VALUES(4,'DP-004: Memory Allocation','Where to allocate data','["stack_prefer", "heap_prefer", "arena", "gc_rely"]','Profile-guided for performance-critical code',NULL);
INSERT INTO decision_points VALUES(5,'DP-005: Lifetime Annotation','How to annotate lifetimes','["elide_all", "annotate_explicit", "use_owned"]','Start with elision, add explicit as needed',NULL);
INSERT INTO decision_points VALUES(6,'DP-006: Ownership Strategy','How to handle shared data','["clone_all", "rc_shared", "borrow_prefer", "arena_all"]','Prefer borrowing, clone for simplicity',NULL);
INSERT INTO decision_points VALUES(7,'DP-007: Closure Conversion','How to convert closures','["box_dyn", "generic_impl", "manual_struct", "fn_pointer"]','Generic impl when possible for performance',NULL);
INSERT INTO decision_points VALUES(8,'DP-008: Macro Expansion','How to handle macro-heavy code','["expand_inline", "preserve_macro", "convert_to_function", "codegen"]','Expand inline for portability',NULL);
INSERT INTO decision_points VALUES(9,'DP-009: Exception Handling','How to convert exceptions','["result_type", "panic", "error_code", "option_type"]','Result type for recoverable errors',NULL);
INSERT INTO decision_points VALUES(10,'DP-010: Effect Translation','How to handle effects','["monad_transform", "direct_io", "effect_handler", "capability"]','Match target language idioms',NULL);
INSERT INTO decision_points VALUES(11,'DP-011: Async Boundary','Where to place async boundaries','["top_level", "per_io", "manual_annotate", "runtime_decide"]','Top-level async for simplicity',NULL);
INSERT INTO decision_points VALUES(12,'DP-012: Concurrency Model','Which concurrency model to use','["threads", "async", "actors", "channels"]','Match target language strengths',NULL);
INSERT INTO decision_points VALUES(13,'DP-013: Protocol Adoption','How to implement protocols/interfaces','["impl_all", "impl_needed", "delegate", "newtype_wrap"]','Implement only what''s used',NULL);
INSERT INTO decision_points VALUES(14,'DP-014: Visibility Mapping','How to map visibility modifiers','["preserve_exact", "widen_to_public", "narrow_to_private", "module_based"]','Preserve exact when possible',NULL);
INSERT INTO decision_points VALUES(15,'DP-015: Package Structure','How to organize modules','["flat", "nested", "workspace", "single_crate"]','Match source structure initially',NULL);
INSERT INTO decision_points VALUES(16,'DP-016: Build Integration','How to integrate with build system','["cargo_only", "cmake_integration", "mixed_build", "manual"]','Native build system preferred',NULL);
